fn runtime_attestation_summary(
    certificate: &GnosisFoilRuntimeCertificate,
    entropy_certificate: Option<&ResidentEntropyCertificate>,
) -> RuntimeAttestationSummary {
    RuntimeAttestationSummary {
        host: certificate.host,
        rf_computable: certificate.rf_computable,
        selected_channels: certificate.selected_channels,
        active_engine_count: certificate.active_engine_count,
        replacement_gap_count: certificate.certification_gaps.len(),
        fano_xor_payload_count: certificate
            .monster_aeon_fano_fast_paths
            .iter()
            .filter(|path| path.xor_payload.is_some())
            .count(),
        first_fano_xor_payload: certificate
            .monster_aeon_fano_fast_paths
            .iter()
            .find_map(|path| path.xor_payload),
        entropy_harvest_units_solved: entropy_certificate
            .map(|cert| cert.units_solved)
            .unwrap_or(0),
        entropy_harvest_units_total: entropy_certificate
            .map(|cert| cert.units_total)
            .unwrap_or(0),
        entropy_harvest_utilization_rate: entropy_certificate
            .map(|cert| cert.solved_rate)
            .unwrap_or(0.0),
    }
}

fn fano_xor_flow_bytes(certificate: &GnosisFoilRuntimeCertificate) -> Vec<u8> {
    fano_xor_flow_packed_route_bytes(certificate).to_vec()
}

