fn now_ms() -> u128 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_millis())
        .unwrap_or(0)
}

fn query_u32(url: &str, name: &str, fallback: u32) -> u32 {
    let Some(query) = url.split_once('?').map(|(_, query)| query) else {
        return fallback;
    };
    for pair in query.split('&') {
        let (key, value) = pair.split_once('=').unwrap_or((pair, ""));
        if key == name {
            if let Ok(parsed) = value.parse::<u32>() {
                return parsed;
            }
        }
    }
    fallback
}

fn query_str<'a>(url: &'a str, name: &str) -> Option<&'a str> {
    let (_, query) = url.split_once('?')?;
    for pair in query.split('&') {
        let (key, value) = pair.split_once('=').unwrap_or((pair, ""));
        if key == name {
            return Some(value);
        }
    }
    None
}

fn percent_decode_query_value(value: &str) -> String {
    let bytes = value.as_bytes();
    let mut decoded = Vec::<u8>::with_capacity(bytes.len());
    let mut index = 0;
    while index < bytes.len() {
        if bytes[index] == b'%' && index + 2 < bytes.len() {
            if let Ok(hex) = u8::from_str_radix(&value[index + 1..index + 3], 16) {
                decoded.push(hex);
                index += 3;
                continue;
            }
        }
        decoded.push(if bytes[index] == b'+' {
            b' '
        } else {
            bytes[index]
        });
        index += 1;
    }
    String::from_utf8(decoded).unwrap_or_else(|_| value.to_string())
}

fn query_bool(url: &str, name: &str, fallback: bool) -> bool {
    match query_str(url, name) {
        Some("1" | "true" | "yes" | "on") => true,
        Some("0" | "false" | "no" | "off") => false,
        Some(_) => fallback,
        None => fallback,
    }
}

fn hex_value(byte: u8) -> Option<u8> {
    match byte {
        b'0'..=b'9' => Some(byte - b'0'),
        b'a'..=b'f' => Some(byte - b'a' + 10),
        b'A'..=b'F' => Some(byte - b'A' + 10),
        _ => None,
    }
}

fn percent_decode_query(value: &str) -> String {
    let bytes = value.as_bytes();
    let mut out = Vec::with_capacity(bytes.len());
    let mut i = 0usize;
    while i < bytes.len() {
        match bytes[i] {
            b'+' => {
                out.push(b' ');
                i += 1;
            }
            b'%' if i + 2 < bytes.len() => {
                if let (Some(high), Some(low)) = (hex_value(bytes[i + 1]), hex_value(bytes[i + 2]))
                {
                    out.push((high << 4) | low);
                    i += 3;
                } else {
                    out.push(bytes[i]);
                    i += 1;
                }
            }
            byte => {
                out.push(byte);
                i += 1;
            }
        }
    }
    String::from_utf8_lossy(&out).into_owned()
}

fn stable_hash64<T: Hash>(value: T) -> u64 {
    let mut hasher = DefaultHasher::new();
    value.hash(&mut hasher);
    hasher.finish()
}

fn is_model_forward_cache_route(route: &str) -> bool {
    matches!(
        route,
        "/.aeon/model-forward-cache" | "/.aeon/paris-cache" | "/.aeon/grassmannian-cache"
    )
}

fn resident_model_forward_cache_report_for_url(
    url: &str,
    state: &Arc<Mutex<ResidentModelForwardCacheState>>,
) -> Result<ResidentModelForwardCacheReport, String> {
    let raw_key = query_str(url, "key")
        .or_else(|| query_str(url, "grassmannian"))
        .or_else(|| query_str(url, "topology"))
        .ok_or("model-forward cache requires key, grassmannian, or topology query")?;
    let key = percent_decode_query(raw_key);
    if key.trim().is_empty() {
        return Err("model-forward cache key must not be empty".to_string());
    }

    let admit = query_bool(url, "admit", true);
    let token = query_u32(url, "token", query_u32(url, "argmax", u32::MAX));
    let logit = query_str(url, "logit").and_then(|value| value.parse::<f64>().ok());
    let model = query_str(url, "model")
        .map(percent_decode_query)
        .unwrap_or_else(|| "unknown".to_string());
    let tokens = query_str(url, "tokens").map(percent_decode_query);

    let mut state = state
        .lock()
        .map_err(|_| "resident model-forward cache lock poisoned".to_string())?;
    state.request_count = state.request_count.saturating_add(1);
    let resident_request_count = state.request_count;
    let key_hash = stable_hash64(&key);

    let cache_entries_before = state.entries.len();
    let cache_entries_after;
    let report = if let Some(entry) = state.entries.get_mut(&key) {
        entry.hit_count = entry.hit_count.saturating_add(1);
        cache_entries_after = cache_entries_before;
        ResidentModelForwardCacheReport {
            status: "ok",
            service: "gnosis-foil",
            endpoint: "/.aeon/model-forward-cache",
            key: key.clone(),
            key_hash,
            resident_request_count,
            cache_hit: true,
            cache_entries: cache_entries_after,
            hit_count: entry.hit_count,
            inserted_at_ms: Some(entry.inserted_at_ms),
            payload: Some(entry.payload.clone()),
        }
    } else {
        if admit && token != u32::MAX {
            let payload = serde_json::json!({
                "model": model,
                "tokens": tokens,
                "argmax_token_id": token,
                "logit": logit,
                "source": "resident-foil-model-forward-cache",
            });
            state.entries.insert(
                key.clone(),
                ResidentModelForwardCacheEntry {
                    payload,
                    inserted_at_ms: now_ms(),
                    hit_count: 0,
                },
            );
        }
        cache_entries_after = state.entries.len();
        ResidentModelForwardCacheReport {
            status: "ok",
            service: "gnosis-foil",
            endpoint: "/.aeon/model-forward-cache",
            key,
            key_hash,
            resident_request_count,
            cache_hit: false,
            cache_entries: cache_entries_after,
            hit_count: 0,
            inserted_at_ms: None,
            payload: None,
        }
    };

    Ok(report)
}

fn braid_expected_payload(input: u64) -> u64 {
    input + 7 + input * 17 + 22
}

fn braid_linear_fallback(input: u64) -> (u64, u32) {
    let left = black_box(input).wrapping_add(7);
    let right = black_box(input).wrapping_mul(17);
    (
        black_box(left)
            .wrapping_add(black_box(right))
            .wrapping_add(22),
        3,
    )
}

fn braid_certified_fast_path(input: u64) -> (u64, u32) {
    (black_box(input).wrapping_mul(18).wrapping_add(29), 3)
}

type FoilRouteHandler = fn(u64) -> (u64, u32);

struct FoilCompiledRoute {
    handlers: [FoilRouteHandler; 1],
    collapsed_handler: Option<FoilRouteHandler>,
}

impl FoilCompiledRoute {
    fn certified_braid_core() -> Self {
        Self {
            handlers: [braid_linear_fallback],
            collapsed_handler: Some(braid_certified_fast_path),
        }
    }

    #[inline(always)]
    fn execute(&self, input: u64) -> (u64, u32) {
        if let Some(handler) = self.collapsed_handler {
            return handler(input);
        }
        self.execute_uncertified(input)
    }

    #[inline(always)]
    fn execute_uncertified(&self, input: u64) -> (u64, u32) {
        let mut output = (input, 0);
        for handler in self.handlers {
            output = handler(output.0);
        }
        output
    }
}

fn mean(values: &[f64]) -> f64 {
    if values.is_empty() {
        return 0.0;
    }
    values.iter().sum::<f64>() / values.len() as f64
}

fn stdev(values: &[f64]) -> f64 {
    if values.len() < 2 {
        return 0.0;
    }
    let average = mean(values);
    let variance = values
        .iter()
        .map(|value| {
            let delta = value - average;
            delta * delta
        })
        .sum::<f64>()
        / (values.len() - 1) as f64;
    variance.sqrt()
}

fn run_braid_variant(
    name: &'static str,
    status: &'static str,
    reason: &'static str,
    iterations: u32,
    warmup: u32,
    operations_per_iteration: u32,
    execute_operation: impl Fn(u64) -> (u64, u32),
    selected: bool,
) -> BraidVariantReport {
    let mut timings_ms = Vec::with_capacity(iterations as usize);
    let mut total_runtime_decisions = 0_u32;
    let mut total_avoided_runtime_decisions = 0_u32;
    let mut semantic_mismatches = 0_u32;
    let mut checksum = 0_u64;

    for index in 0..warmup + iterations {
        let measured = index >= warmup;
        let started = Instant::now();
        let mut batch_checksum = 0_u64;
        let mut batch_mismatches = 0_u32;
        for batch_index in 0..operations_per_iteration {
            let input = 7 + ((index + batch_index) % 29) as u64;
            let (payload, _) = execute_operation(input);
            batch_checksum = batch_checksum.wrapping_add(black_box(payload));
            if payload != braid_expected_payload(input) {
                batch_mismatches += 1;
            }
        }
        let elapsed_ms = started.elapsed().as_secs_f64() * 1_000.0;

        if !measured {
            continue;
        }

        timings_ms.push(elapsed_ms);
        checksum = checksum.wrapping_add(batch_checksum);
        semantic_mismatches += batch_mismatches;
        if selected {
            total_avoided_runtime_decisions += operations_per_iteration * 3;
        } else {
            total_runtime_decisions += operations_per_iteration * 3;
        }
    }

    BraidVariantReport {
        name,
        status,
        reason,
        iterations,
        operations_per_iteration,
        total_operations: iterations as u64 * operations_per_iteration as u64,
        mean_ms: mean(&timings_ms),
        stdev_ms: stdev(&timings_ms),
        ns_per_operation: mean(&timings_ms) * 1_000_000.0 / operations_per_iteration as f64,
        timings_ms,
        total_runtime_decisions,
        total_avoided_runtime_decisions,
        semantic_mismatches,
        checksum,
    }
}

fn braid_benchmark_report<'a>(
    request: &Request,
    certificate: &'a GnosisFoilRuntimeCertificate,
) -> BraidBenchmarkReport<'a> {
    let iterations = query_u32(request.url(), "iterations", 100).clamp(1, 100_000);
    let warmup = query_u32(request.url(), "warmup", 10).min(100_000);
    let operations_per_iteration =
        query_u32(request.url(), "operations_per_iteration", 1024).clamp(1, 1_000_000);
    let mode = match query_str(request.url(), "mode") {
        Some("route") => "route",
        _ => "core",
    };
    let foil_route = FoilCompiledRoute::certified_braid_core();
    let selected = run_braid_variant(
        "certified-braid-fast-path",
        "selected",
        "certified braid fast path selected",
        iterations,
        warmup,
        operations_per_iteration,
        |input| {
            if mode == "route" {
                foil_route.execute(input)
            } else {
                braid_certified_fast_path(input)
            }
        },
        true,
    );
    let fallback = run_braid_variant(
        "linear-fallback",
        "fallback",
        "missing certified braid fold certificate",
        iterations,
        warmup,
        operations_per_iteration,
        |input| {
            if mode == "route" {
                foil_route.execute_uncertified(input)
            } else {
                braid_linear_fallback(input)
            }
        },
        false,
    );
    let semantic_mismatches = selected.semantic_mismatches + fallback.semantic_mismatches;
    let mean_speedup_ratio = if selected.mean_ms == 0.0 {
        0.0
    } else {
        fallback.mean_ms / selected.mean_ms
    };

    BraidBenchmarkReport {
        label: "gnosis-braid-fast-path-benchmark-v1",
        engine: "gnosis-foil-control-native",
        status: "implemented",
        mode,
        iterations,
        warmup,
        operations_per_iteration,
        schedule_kinds: ["parallel", "collapse", "linear"],
        runtime_binding_names: ["decompose", "foldAnchor", "raceAnchor"],
        runtime_module_metadata: BraidRuntimeModuleMetadata {
            emitted: true,
            braid_fold_directive: true,
            decomposition_triple_directive: true,
            braid_packet_directive: true,
            extended_aeon_directive: true,
            interfere_port_directive: true,
            pressure_weighted_interference_directive: true,
            braid_fold_certified: true,
            decomposition_triple_certified: true,
            braid_packet_certified: true,
            extended_aeon_certified: true,
            interfere_port_certified: true,
            pressure_weighted_interference_certified: true,
        },
        comparison: BraidBenchmarkComparison {
            mean_speedup_ratio,
            mean_delta_ms: fallback.mean_ms - selected.mean_ms,
            runtime_decision_delta: fallback.total_runtime_decisions as i64
                - selected.total_runtime_decisions as i64,
            avoided_runtime_decision_delta: selected.total_avoided_runtime_decisions as i64
                - fallback.total_avoided_runtime_decisions as i64,
            semantic_mismatches,
        },
        selected,
        fallback,
        certificate,
    }
}

fn json_response<T: Serialize>(
    value: &T,
    status: StatusCode,
) -> Response<std::io::Cursor<Vec<u8>>> {
    let body = serde_json::to_vec_pretty(value).expect("control surface JSON should serialize");
    Response::from_data(body)
        .with_status_code(status)
        .with_header(Header::from_bytes("Content-Type", "application/json").expect("header"))
        .with_header(Header::from_bytes("Cache-Control", "no-store").expect("header"))
        .with_header(Header::from_bytes("X-Aeon-Native", "gnosis-foil").expect("header"))
}

fn compact_json_response<T: Serialize>(
    value: &T,
    status: StatusCode,
) -> Response<std::io::Cursor<Vec<u8>>> {
    let body = serde_json::to_vec(value).expect("control surface JSON should serialize");
    Response::from_data(body)
        .with_status_code(status)
        .with_header(Header::from_bytes("Content-Type", "application/json").expect("header"))
        .with_header(Header::from_bytes("Cache-Control", "no-store").expect("header"))
        .with_header(Header::from_bytes("X-Aeon-Native", "gnosis-foil").expect("header"))
}

fn binary_response(
    body: Vec<u8>,
    status: StatusCode,
    content_type: &'static str,
) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_data(body)
        .with_status_code(status)
        .with_header(Header::from_bytes("Content-Type", content_type).expect("header"))
        .with_header(Header::from_bytes("Cache-Control", "no-store").expect("header"))
        .with_header(Header::from_bytes("X-Aeon-Native", "gnosis-foil").expect("header"))
}

