fn origin(request: &Request, cli: &Cli) -> String {
    let host = request
        .headers()
        .iter()
        .find(|header| header.field.equiv("Host"))
        .map(|header| header.value.as_str().to_string())
        .unwrap_or_else(|| format!("{}:{}", cli.host, cli.port));
    format!("http://{host}")
}

fn request_host_name(request: &Request, cli: &Cli) -> String {
    request
        .headers()
        .iter()
        .find(|header| header.field.equiv("Host"))
        .and_then(|header| header.value.as_str().split(':').next())
        .filter(|host| !host.is_empty())
        .unwrap_or(&cli.host)
        .to_string()
}

fn flow_endpoint(request: &Request, cli: &Cli) -> EndpointSurface {
    if cli.flow_enabled {
        EndpointSurface {
            endpoint: Some(format!(
                "aeon://{}:{}",
                request_host_name(request, cli),
                cli.flow_port
            )),
            status: "available",
            description: "Native gnosis-foil UDP listener accepting uring-compatible 10-byte Aeon Flow frames.",
        }
    } else {
        EndpointSurface {
            endpoint: None,
            status: "disabled",
            description: "Flow/UDP listener disabled by --no-flow.",
        }
    }
}

fn loopback_proxy_endpoint(cli: &Cli) -> EndpointSurface {
    if let Some(upstream) = &cli.proxy_upstream {
        EndpointSurface {
            endpoint: Some(format!("http://{}:{}", upstream.host, upstream.port)),
            status: "available",
            description: "Loopback app shell behind gnosis-foil.",
        }
    } else {
        EndpointSurface {
            endpoint: None,
            status: "disabled",
            description: "Loopback proxy disabled; start with --proxy-all and --proxy-upstream-port to front an app shell.",
        }
    }
}

fn parse_flow_path(payload: &[u8]) -> Option<String> {
    if payload.starts_with(b"/") {
        let path_end = payload
            .iter()
            .position(|byte| byte.is_ascii_whitespace())
            .unwrap_or(payload.len());
        return std::str::from_utf8(&payload[..path_end])
            .ok()
            .map(str::to_string);
    }

    let request = std::str::from_utf8(payload).ok()?;
    if !request.starts_with("GET ") {
        return None;
    }
    let rest = &request[4..];
    let path_end = rest.find(char::is_whitespace)?;
    Some(rest[..path_end].to_string())
}

fn is_rf_fibonacci_route(route: &str) -> bool {
    matches!(route, "/.aeon/rf-fibonacci" | "/.aeon/fib20-rf")
}

fn compact_json<T: Serialize>(value: &T) -> Vec<u8> {
    serde_json::to_vec(value).expect("control surface JSON should serialize")
}

fn sanitize_token_part(value: &str) -> String {
    value
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || matches!(ch, ':' | '.' | '_' | '-') {
                ch.to_ascii_lowercase()
            } else {
                '-'
            }
        })
        .collect::<String>()
        .trim_matches('-')
        .to_string()
}

fn r1_phyle_entropy_surface_for_url(url: &str) -> Result<R1PhyleEntropySurface, String> {
    let now = now_ms().min(u128::from(u64::MAX)) as u64;
    let device_id = query_str(url, "deviceId")
        .or_else(|| query_str(url, "device_id"))
        .unwrap_or("did:aeon:device:r1")
        .trim()
        .to_string();
    if device_id.is_empty() {
        return Err("deviceId must be nonempty".to_string());
    }
    let phyle_id = query_str(url, "phyleId")
        .or_else(|| query_str(url, "phyle_id"))
        .unwrap_or("phyle:r1-room")
        .trim()
        .to_string();
    if phyle_id.is_empty() {
        return Err("phyleId must be nonempty".to_string());
    }
    let sink_process_id = query_str(url, "sinkProcessId")
        .or_else(|| query_str(url, "sink_process_id"))
        .unwrap_or("monster:foil")
        .trim()
        .to_string();
    if sink_process_id.is_empty() {
        return Err("sinkProcessId must be nonempty".to_string());
    }
    let surplus_units =
        query_u32(url, "surplusUnits", query_u32(url, "surplus_units", 6)).min(64) as u16;
    let accepted_units = query_u32(
        url,
        "acceptedUnits",
        query_u32(url, "accepted_units", u32::from(surplus_units)),
    )
    .min(u32::from(surplus_units)) as u16;
    let escrowed_units = query_u32(
        url,
        "escrowedUnits",
        query_u32(
            url,
            "escrowed_units",
            u32::from(surplus_units.saturating_sub(accepted_units)),
        ),
    )
    .min(u32::from(surplus_units)) as u16;
    if accepted_units.saturating_add(escrowed_units) != surplus_units {
        return Err("acceptedUnits + escrowedUnits must equal surplusUnits".to_string());
    }
    let entropy_word = query_u32(url, "entropyWord", query_u32(url, "entropy_word", 69))
        .min(u32::from(u16::MAX)) as u16;
    let cadence_ms = Some(query_u32(
        url,
        "cadenceMs",
        query_u32(url, "cadence_ms", 1_000),
    ));
    let ttl_ms = query_u32(url, "ttlMs", query_u32(url, "ttl_ms", 60_000)) as u64;
    let redelivery_token = format!(
        "r1-phyle-redelivery:{}:{}:{}:{}:{:x}",
        sanitize_token_part(&phyle_id),
        sanitize_token_part(&sink_process_id),
        sanitize_token_part(&device_id),
        now,
        entropy_word
    );
    let envelope = R1PhyleEntropyEnvelope {
        schema_version: R1_PHYLE_ENTROPY_SCHEMA_VERSION.to_string(),
        contract_id: R1_PHYLE_ENTROPY_CONTRACT_ID.to_string(),
        egress: "PhyleEntropyEscrow".to_string(),
        theorem_id: R1_PHYLE_ENTROPY_THEOREM_ID.to_string(),
        executable: false,
        device_id: device_id.clone(),
        phyle_id: phyle_id.clone(),
        sink_process_id: sink_process_id.clone(),
        surplus_units,
        accepted_units,
        escrowed_units,
        redelivery_token,
        entropy_word,
        cadence_ms,
        timestamp_ms: now,
        expires_at_ms: now.saturating_add(ttl_ms),
        projection: build_protocol69_projection_envelope(),
    };
    Ok(R1PhyleEntropySurface {
        status: "ok",
        service: "gnosis-foil",
        transport: "http",
        phyle_id,
        sink_process_id,
        device_id,
        envelope,
    })
}

fn validate_r1_worksteal_hint(hint: &R1WorkStealHint) -> Result<(), String> {
    if hint.schema_version != R1_WORKSTEAL_HINT_SCHEMA_VERSION {
        return Err("schemaVersion mismatch".to_string());
    }
    if hint.contract_id != R1_WORKSTEAL_HINT_CONTRACT_ID {
        return Err("contractId mismatch".to_string());
    }
    if hint.theorem_id != R1_WORKSTEAL_HINT_THEOREM_ID {
        return Err("theoremId mismatch".to_string());
    }
    if hint.executable {
        return Err("work-steal hints are non-executable".to_string());
    }
    if hint.hint_id.trim().is_empty() {
        return Err("hintId must be nonempty".to_string());
    }
    if hint.producer_device_id.trim().is_empty() {
        return Err("producerDeviceId must be nonempty".to_string());
    }
    if hint.target_phyle_id.trim().is_empty() {
        return Err("targetPhyleId must be nonempty".to_string());
    }
    if hint.work_kind != "fibonacci" && hint.work_kind != "qwen-knot" {
        return Err("workKind must be fibonacci or qwen-knot".to_string());
    }
    if hint.n > 93 {
        return Err("n must be an integer in [0, 93]".to_string());
    }
    if hint.work_kind == "qwen-knot"
        && (hint
            .model_id
            .as_ref()
            .is_none_or(|value| value.trim().is_empty())
            || hint
                .knot_id
                .as_ref()
                .is_none_or(|value| value.trim().is_empty())
            || hint
                .knot_hash
                .as_ref()
                .is_none_or(|value| value.trim().is_empty())
            || hint
                .token_budget
                .is_none_or(|value| value == 0 || value > 4096))
        {
            return Err(
                "qwen-knot hints require modelId, knotId, knotHash, and bounded tokenBudget"
                    .to_string(),
            );
        }
    if hint.ttl_ms == 0 {
        return Err("ttlMs must be positive".to_string());
    }
    if let Some(witness_window_hash) = hint.witness_window_hash.as_ref() {
        if witness_window_hash.trim().is_empty() {
            return Err("witnessWindowHash must be nonempty".to_string());
        }
    }
    validate_protocol69_projection_envelope(&hint.projection)?;
    Ok(())
}

fn resident_r1_worksteal_receipt_for_hint(
    hint: &R1WorkStealHint,
    worker_device_id: &str,
) -> Result<R1ComputeReceipt, String> {
    validate_r1_worksteal_hint(hint)?;
    if worker_device_id.trim().is_empty() {
        return Err("workerDeviceId must be nonempty".to_string());
    }

    let compute_started = Instant::now();
    let result = if hint.work_kind == "fibonacci" {
        expected_fibonacci(hint.n)
            .ok_or_else(|| "fibonacci hint n is outside computable range".to_string())?
            .to_string()
    } else {
        format!(
            "qwen-knot:{}:{}:{}:{}",
            hint.model_id.as_deref().unwrap_or(""),
            hint.knot_id.as_deref().unwrap_or(""),
            hint.knot_hash.as_deref().unwrap_or(""),
            hint.token_budget.unwrap_or(0)
        )
    };
    let compute_ns = compute_started.elapsed().as_nanos();

    let validation_started = Instant::now();
    let digest_input = format!(
        "{}:{}:{}:{}:{}:{}:{}:{}",
        R1_COMPUTE_RECEIPT_CONTRACT_ID,
        hint.target_phyle_id,
        hint.work_kind,
        hint.n,
        hint.model_id.as_deref().unwrap_or(""),
        hint.knot_id.as_deref().unwrap_or(""),
        hint.knot_hash.as_deref().unwrap_or(""),
        result
    );
    let mut hasher = DefaultHasher::new();
    digest_input.hash(&mut hasher);
    let result_digest = format!("siphash:{:016x}", hasher.finish());
    let beam_cache_key = format!(
        "beam:protocol69:{}:{}:{}:{}",
        hint.target_phyle_id, hint.work_kind, hint.n, result_digest
    );
    let validation_ns = validation_started.elapsed().as_nanos();

    Ok(R1ComputeReceipt {
        schema_version: R1_COMPUTE_RECEIPT_SCHEMA_VERSION.to_string(),
        contract_id: R1_COMPUTE_RECEIPT_CONTRACT_ID.to_string(),
        theorem_id: R1_COMPUTE_RECEIPT_THEOREM_ID.to_string(),
        authority: "reuse-right".to_string(),
        executable: false,
        hint_id: hint.hint_id.clone(),
        worker_device_id: worker_device_id.trim().to_string(),
        target_phyle_id: hint.target_phyle_id.clone(),
        work_kind: hint.work_kind.clone(),
        n: hint.n,
        model_id: hint.model_id.clone(),
        knot_id: hint.knot_id.clone(),
        knot_hash: hint.knot_hash.clone(),
        token_budget: hint.token_budget,
        result,
        result_digest,
        compute_ns,
        validation_ns,
        timestamp_ms: now_ms().min(u128::from(u64::MAX)) as u64,
        beam_cache_key,
        witness_window_hash: hint.witness_window_hash.clone(),
        projection: build_protocol69_projection_envelope(),
    })
}

fn parse_r1_worksteal_hint(body: &[u8]) -> Result<R1WorkStealHint, String> {
    let hint: R1WorkStealHint = serde_json::from_slice(body)
        .map_err(|error| format!("invalid R1 work-steal body: {error}"))?;
    validate_r1_worksteal_hint(&hint)?;
    Ok(hint)
}

fn r1_worksteal_response_for_hint(
    hint: R1WorkStealHint,
    worker_device_id: &str,
) -> Result<R1WorkStealResponse, String> {
    let receipt = resident_r1_worksteal_receipt_for_hint(&hint, worker_device_id)?;
    Ok(R1WorkStealResponse {
        status: "accepted",
        service: "gnosis-foil",
        transport: "http",
        accepted: true,
        interpretation:
            "R1 fat clients may try deterministic work hints and return reuse-right receipts; receipts do not grant executable authority.",
        hint,
        receipt,
    })
}

fn validate_r1_compute_receipt(receipt: &R1ComputeReceipt) -> Result<(), String> {
    if receipt.schema_version != R1_COMPUTE_RECEIPT_SCHEMA_VERSION {
        return Err("schemaVersion mismatch".to_string());
    }
    if receipt.contract_id != R1_COMPUTE_RECEIPT_CONTRACT_ID {
        return Err("contractId mismatch".to_string());
    }
    if receipt.theorem_id != R1_COMPUTE_RECEIPT_THEOREM_ID {
        return Err("theoremId mismatch".to_string());
    }
    if receipt.authority != "reuse-right" {
        return Err("receipt authority must be reuse-right".to_string());
    }
    if receipt.executable {
        return Err("compute receipts are non-executable".to_string());
    }
    if receipt.hint_id.trim().is_empty() {
        return Err("hintId must be nonempty".to_string());
    }
    if receipt.worker_device_id.trim().is_empty() {
        return Err("workerDeviceId must be nonempty".to_string());
    }
    if receipt.target_phyle_id.trim().is_empty() {
        return Err("targetPhyleId must be nonempty".to_string());
    }
    if receipt.work_kind != "fibonacci" && receipt.work_kind != "qwen-knot" {
        return Err("workKind must be fibonacci or qwen-knot".to_string());
    }
    if receipt.n > 93 {
        return Err("n must be an integer in [0, 93]".to_string());
    }
    if receipt.result.trim().is_empty() {
        return Err("result must be nonempty".to_string());
    }
    if receipt.result_digest.trim().is_empty() {
        return Err("resultDigest must be nonempty".to_string());
    }
    if receipt.beam_cache_key.trim().is_empty() {
        return Err("beamCacheKey must be nonempty".to_string());
    }
    validate_protocol69_projection_envelope(&receipt.projection)?;
    Ok(())
}

fn validate_r1_receipt_submission(submission: &R1WorkStealReceiptSubmission) -> Result<(), String> {
    if submission.schema_version != R1_WORKSTEAL_RECEIPT_SUBMISSION_SCHEMA_VERSION {
        return Err("schemaVersion mismatch".to_string());
    }
    if submission.contract_id != R1_WORKSTEAL_RECEIPT_SUBMISSION_CONTRACT_ID {
        return Err("contractId mismatch".to_string());
    }
    if submission.theorem_id != R1_WORKSTEAL_RECEIPT_SUBMISSION_THEOREM_ID {
        return Err("theoremId mismatch".to_string());
    }
    if submission.executable {
        return Err("receipt submissions are non-executable".to_string());
    }
    if submission.claim_id.trim().is_empty() {
        return Err("claimId must be nonempty".to_string());
    }
    validate_r1_compute_receipt(&submission.receipt)?;
    validate_protocol69_projection_envelope(&submission.projection)?;
    Ok(())
}

fn parse_r1_worksteal_seed_body(body: &[u8]) -> Result<Vec<R1WorkStealHint>, String> {
    let post_body: R1WorkStealSeedBody = serde_json::from_slice(body)
        .map_err(|error| format!("invalid R1 work-steal seed body: {error}"))?;
    let hints = match post_body {
        R1WorkStealSeedBody::Single(hint) => vec![hint],
        R1WorkStealSeedBody::Batch(hints) => hints,
    };
    if hints.is_empty() {
        return Err("R1 work-steal seed batch must not be empty".to_string());
    }
    if hints.len() > R1_WORKSTEAL_QUEUE_LIMIT {
        return Err(format!(
            "R1 work-steal seed batch exceeds limit {R1_WORKSTEAL_QUEUE_LIMIT}"
        ));
    }
    for hint in &hints {
        validate_r1_worksteal_hint(hint)?;
    }
    Ok(hints)
}

fn parse_r1_worksteal_receipt_submission(
    body: &[u8],
) -> Result<R1WorkStealReceiptSubmission, String> {
    let submission: R1WorkStealReceiptSubmission = serde_json::from_slice(body)
        .map_err(|error| format!("invalid R1 work-steal receipt body: {error}"))?;
    validate_r1_receipt_submission(&submission)?;
    Ok(submission)
}

fn r1_queue_summary(state: &R1WorkStealQueueState) -> R1WorkStealQueueSummary {
    let mut per_phyle: HashMap<String, R1WorkStealPhyleQueueSummary> = HashMap::new();

    for entry in &state.pending {
        let summary = per_phyle
            .entry(entry.hint.target_phyle_id.clone())
            .or_insert_with(|| R1WorkStealPhyleQueueSummary {
                phyle_id: entry.hint.target_phyle_id.clone(),
                pending: 0,
                claimed: 0,
                accepted: 0,
                rejected: 0,
                completed_units: 0,
            });
        summary.pending = summary.pending.saturating_add(1);
    }
    for entry in state.claimed.values() {
        let summary = per_phyle
            .entry(entry.hint.target_phyle_id.clone())
            .or_insert_with(|| R1WorkStealPhyleQueueSummary {
                phyle_id: entry.hint.target_phyle_id.clone(),
                pending: 0,
                claimed: 0,
                accepted: 0,
                rejected: 0,
                completed_units: 0,
            });
        summary.claimed = summary.claimed.saturating_add(1);
    }
    for receipt in &state.accepted_receipts {
        let summary = per_phyle
            .entry(receipt.target_phyle_id.clone())
            .or_insert_with(|| R1WorkStealPhyleQueueSummary {
                phyle_id: receipt.target_phyle_id.clone(),
                pending: 0,
                claimed: 0,
                accepted: 0,
                rejected: 0,
                completed_units: 0,
            });
        summary.accepted = summary.accepted.saturating_add(1);
        summary.completed_units = summary.completed_units.saturating_add(1);
    }

    let mut per_phyle_values = per_phyle.into_values().collect::<Vec<_>>();
    per_phyle_values.sort_by(|left, right| left.phyle_id.cmp(&right.phyle_id));

    R1WorkStealQueueSummary {
        schema_version: R1_WORKSTEAL_QUEUE_SUMMARY_SCHEMA_VERSION.to_string(),
        contract_id: R1_WORKSTEAL_QUEUE_SUMMARY_CONTRACT_ID.to_string(),
        pending: state.pending.len() as u64,
        claimed: state.claimed.len() as u64,
        accepted: state.accepted_receipts.len() as u64,
        rejected: state.rejected_receipts,
        per_phyle: per_phyle_values,
        timestamp_ms: now_ms().min(u128::from(u64::MAX)) as u64,
    }
}

fn seed_r1_worksteal_queue(
    state: &mut R1WorkStealQueueState,
    hints: Vec<R1WorkStealHint>,
) -> Result<R1WorkStealSeedResponse, String> {
    if state.pending.len().saturating_add(hints.len()) > R1_WORKSTEAL_QUEUE_LIMIT {
        return Err(format!(
            "R1 work-steal queue exceeds limit {R1_WORKSTEAL_QUEUE_LIMIT}"
        ));
    }
    let seeded = hints.len();
    for hint in hints {
        state.pending.push_back(R1WorkStealQueueEntry {
            hint,
            claim_id: None,
            claimed_by: None,
            claimed_at_ms: None,
        });
    }
    Ok(R1WorkStealSeedResponse {
        status: "seeded",
        service: "gnosis-foil",
        transport: "http",
        seeded,
        summary: r1_queue_summary(state),
    })
}

fn r1_claim_id_component(value: &str) -> String {
    value
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.' | '~') {
                ch
            } else {
                ':'
            }
        })
        .collect()
}

fn claim_r1_worksteal_hint(
    state: &mut R1WorkStealQueueState,
    worker_device_id: &str,
    phyle_id: &str,
) -> Result<R1WorkStealClaim, String> {
    if worker_device_id.trim().is_empty() {
        return Err("workerDeviceId must be nonempty".to_string());
    }
    if phyle_id.trim().is_empty() {
        return Err("phyleId must be nonempty".to_string());
    }

    let matching_index = state
        .pending
        .iter()
        .position(|entry| entry.hint.target_phyle_id == phyle_id);
    let Some(index) = matching_index else {
        return Ok(R1WorkStealClaim {
            schema_version: R1_WORKSTEAL_CLAIM_SCHEMA_VERSION.to_string(),
            contract_id: R1_WORKSTEAL_CLAIM_CONTRACT_ID.to_string(),
            theorem_id: R1_WORKSTEAL_CLAIM_THEOREM_ID.to_string(),
            executable: false,
            status: "idle".to_string(),
            worker_device_id: worker_device_id.trim().to_string(),
            phyle_id: phyle_id.trim().to_string(),
            claim_id: None,
            hint: None,
            summary: r1_queue_summary(state),
            timestamp_ms: now_ms().min(u128::from(u64::MAX)) as u64,
            projection: build_protocol69_projection_envelope(),
        });
    };

    let mut entry = state
        .pending
        .remove(index)
        .ok_or_else(|| "pending queue index disappeared".to_string())?;
    let claim_id = format!(
        "claim:{}:{}",
        r1_claim_id_component(worker_device_id.trim()),
        r1_claim_id_component(&entry.hint.hint_id)
    );
    entry.claim_id = Some(claim_id.clone());
    entry.claimed_by = Some(worker_device_id.trim().to_string());
    entry.claimed_at_ms = Some(now_ms().min(u128::from(u64::MAX)) as u64);
    let hint = entry.hint.clone();
    state.claimed.insert(claim_id.clone(), entry);

    Ok(R1WorkStealClaim {
        schema_version: R1_WORKSTEAL_CLAIM_SCHEMA_VERSION.to_string(),
        contract_id: R1_WORKSTEAL_CLAIM_CONTRACT_ID.to_string(),
        theorem_id: R1_WORKSTEAL_CLAIM_THEOREM_ID.to_string(),
        executable: false,
        status: "claimed".to_string(),
        worker_device_id: worker_device_id.trim().to_string(),
        phyle_id: phyle_id.trim().to_string(),
        claim_id: Some(claim_id),
        hint: Some(hint),
        summary: r1_queue_summary(state),
        timestamp_ms: now_ms().min(u128::from(u64::MAX)) as u64,
        projection: build_protocol69_projection_envelope(),
    })
}

fn accept_r1_worksteal_receipt(
    state: &mut R1WorkStealQueueState,
    submission: R1WorkStealReceiptSubmission,
) -> Result<R1WorkStealReceiptResponse, String> {
    let entry = state
        .claimed
        .remove(&submission.claim_id)
        .ok_or_else(|| "claimId is not active".to_string())?;
    if entry.hint.hint_id != submission.receipt.hint_id {
        state.rejected_receipts = state.rejected_receipts.saturating_add(1);
        return Err("receipt hintId does not match claim".to_string());
    }
    if entry.hint.target_phyle_id != submission.receipt.target_phyle_id {
        state.rejected_receipts = state.rejected_receipts.saturating_add(1);
        return Err("receipt targetPhyleId does not match claim".to_string());
    }
    if entry.hint.work_kind != submission.receipt.work_kind || entry.hint.n != submission.receipt.n
    {
        state.rejected_receipts = state.rejected_receipts.saturating_add(1);
        return Err("receipt work descriptor does not match claim".to_string());
    }
    if entry.claimed_by.as_deref() != Some(submission.receipt.worker_device_id.as_str()) {
        state.rejected_receipts = state.rejected_receipts.saturating_add(1);
        return Err("receipt workerDeviceId does not match claim".to_string());
    }
    let now = now_ms().min(u128::from(u64::MAX)) as u64;
    if now.saturating_sub(entry.hint.timestamp_ms) > u64::from(entry.hint.ttl_ms) {
        state.rejected_receipts = state.rejected_receipts.saturating_add(1);
        return Err("receipt arrived after hint ttl".to_string());
    }

    let receipt = submission.receipt;
    state.accepted_receipts.push(receipt.clone());
    Ok(R1WorkStealReceiptResponse {
        status: "accepted",
        service: "gnosis-foil",
        transport: "http",
        accepted: true,
        summary: r1_queue_summary(state),
        receipt,
    })
}

fn parse_protocol69_workflow_seed_body(
    body: &[u8],
) -> Result<Vec<Protocol69WorkflowFrame>, String> {
    let post_body: Protocol69WorkflowSeedBody = serde_json::from_slice(body)
        .map_err(|error| format!("invalid protocol69 workflow seed body: {error}"))?;
    let frames = match post_body {
        Protocol69WorkflowSeedBody::Single(frame) => vec![frame],
        Protocol69WorkflowSeedBody::Batch(frames) => frames,
    };
    if frames.is_empty() {
        return Err("protocol69 workflow seed batch must not be empty".to_string());
    }
    for frame in &frames {
        validate_protocol69_workflow_frame(frame)?;
    }
    Ok(frames)
}

fn seed_protocol69_workflow_queue(
    state: &mut Protocol69DispatchQueueState,
    frames: Vec<Protocol69WorkflowFrame>,
) -> Result<Protocol69WorkflowSeedResponse, String> {
    let seeded = frames.len();
    let mut summary = state.summary();
    for frame in frames {
        summary = state.enqueue(frame)?;
    }
    Ok(Protocol69WorkflowSeedResponse {
        status: "seeded",
        service: "gnosis-foil",
        transport: "http",
        seeded,
        summary,
    })
}

fn parse_protocol69_workflow_claim_body(body: &[u8]) -> Result<Protocol69InRoomAgent, String> {
    let agent: Protocol69InRoomAgent = serde_json::from_slice(body)
        .map_err(|error| format!("invalid protocol69 workflow claim body: {error}"))?;
    Protocol69InRoomAgent::new(agent.agent_id, agent.executor, agent.skills)
}

fn parse_protocol69_agent_ack(body: &[u8]) -> Result<Protocol69AgentAck, String> {
    let ack: Protocol69AgentAck = serde_json::from_slice(body)
        .map_err(|error| format!("invalid protocol69 workflow ack body: {error}"))?;
    ack.validate()?;
    Ok(ack)
}

fn accept_protocol69_agent_ack(
    state: &mut Protocol69DispatchQueueState,
    ack: Protocol69AgentAck,
) -> Result<Protocol69WorkflowAckResponse, String> {
    let summary = state.accept_ack(ack)?;
    Ok(Protocol69WorkflowAckResponse {
        status: "accepted",
        service: "gnosis-foil",
        transport: "http",
        accepted: true,
        summary,
    })
}

fn parse_protocol69_network_workflow_seed_body(
    body: &[u8],
) -> Result<Protocol69NetworkWorkflowSeedBody, String> {
    let seed: Protocol69NetworkWorkflowSeedBody = serde_json::from_slice(body)
        .map_err(|error| format!("invalid protocol69 network seed body: {error}"))?;
    if seed.node_id.trim().is_empty() {
        return Err("protocol69 network seed nodeId must be nonempty".to_string());
    }
    if seed.frames.is_empty() {
        return Err("protocol69 network seed frames must not be empty".to_string());
    }
    for frame in &seed.frames {
        validate_protocol69_workflow_frame(frame)?;
    }
    Ok(seed)
}

fn seed_protocol69_network_workflow_queue(
    state: &mut Protocol69AntiqueueNetworkState,
    seed: Protocol69NetworkWorkflowSeedBody,
) -> Result<Protocol69NetworkWorkflowSeedResponse, String> {
    let node_id = seed.node_id.trim().to_string();
    let seeded = seed.frames.len();
    let mut summary = state.summary();
    for frame in seed.frames {
        summary = state.enqueue_on_node(node_id.clone(), frame)?;
    }
    Ok(Protocol69NetworkWorkflowSeedResponse {
        status: "seeded",
        service: "gnosis-foil",
        transport: "http",
        node_id,
        seeded,
        summary,
    })
}

fn accept_protocol69_network_agent_ack(
    state: &mut Protocol69AntiqueueNetworkState,
    ack: Protocol69AgentAck,
) -> Result<Protocol69NetworkWorkflowAckResponse, String> {
    let summary = state.accept_ack(ack)?;
    Ok(Protocol69NetworkWorkflowAckResponse {
        status: "accepted",
        service: "gnosis-foil",
        transport: "http",
        accepted: true,
        summary,
    })
}

fn resident_rf_fibonacci_binary_payload_for_url(
    url: &str,
    cli: &Cli,
    resident_rf_fibonacci: &Arc<Mutex<ResidentRfFibonacciState>>,
) -> Vec<u8> {
    if let Ok(mut state) = resident_rf_fibonacci.lock() {
        if let Some(cached) = state.binary_response_cache.get(url).cloned() {
            state.request_count = state.request_count.saturating_add(1);
            let mut bytes = cached;
            bytes[104..112].copy_from_slice(&state.request_count.to_le_bytes());
            return bytes;
        }
    }

    match resident_rf_fibonacci_report_for_url(url, cli, resident_rf_fibonacci) {
        Ok(report) => {
            let bytes = ResidentRfFibonacciBinaryReport::from_report(&report)
                .to_bytes()
                .to_vec();
            if let Ok(mut state) = resident_rf_fibonacci.lock() {
                state
                    .binary_response_cache
                    .entry(url.to_string())
                    .or_insert_with(|| bytes.clone());
            }
            bytes
        }
        Err(error) => compact_json(&serde_json::json!({
            "status": "error",
            "service": "gnosis-foil",
            "transport": "flow-udp",
            "reason": error,
        })),
    }
}

fn flow_payload_for_path(
    path: &str,
    certificate: &GnosisFoilRuntimeCertificate,
    entropy_certificate: Option<&ResidentEntropyCertificate>,
    cli: &Cli,
    resident_rf_fibonacci: &Arc<Mutex<ResidentRfFibonacciState>>,
    resident_model_forward_cache: &Arc<Mutex<ResidentModelForwardCacheState>>,
) -> Vec<u8> {
    let route = path.split('?').next().unwrap_or(path);
    match route {
        "/" | "/.aeon/health" => compact_json(&serde_json::json!({
            "status": "ok",
            "service": "gnosis-foil",
            "runtime": "gnosis",
            "transport": "flow-udp",
            "frame_header_bytes": distributed_inference::gnosis_foil::FLOW_HEADER_SIZE,
        })),
        "/plaintext" => b"Hello, World!".to_vec(),
        "/json" => compact_json(&serde_json::json!({ "message": "Hello, World!" })),
        "/.aeon/runtime-attestation" => compact_json(&RuntimeAttestationSurface {
            source: "gnosis-foil-control",
            transport: "flow-udp",
            attestation: certificate,
            async_loser_queue_telemetry_theorem_ids: foil_async_loser_queue_telemetry_theorem_ids(),
            summary: runtime_attestation_summary(certificate, entropy_certificate),
            entropy_certificate,
        }),
        "/.aeon/fano-xor" => compact_json(&serde_json::json!({
            "status": "available",
            "service": "gnosis-foil",
            "transport": "flow-udp",
            "fano_xor": runtime_attestation_summary(certificate, entropy_certificate),
        })),
        "/.aeon/fano-xor.bytes" => fano_xor_flow_bytes(certificate),
        "/.aeon/flow" | "/.aeon/udp" => compact_json(&serde_json::json!({
            "status": "available",
            "service": "gnosis-foil",
            "transport": "flow-udp",
            "compatible_with": "gnosis-uring",
        })),
        "/.aeon/protocol69" => compact_json(&serde_json::json!({
            "status": "ok",
            "service": "gnosis-foil",
            "transport": "flow-udp",
            "projection": build_protocol69_projection_envelope(),
        })),
        route if is_rf_fibonacci_route(route) => {
            resident_rf_fibonacci_binary_payload_for_url(path, cli, resident_rf_fibonacci)
        }
        route if is_model_forward_cache_route(route) => {
            match resident_model_forward_cache_report_for_url(path, resident_model_forward_cache) {
                Ok(report) => compact_json(&report),
                Err(error) => compact_json(&serde_json::json!({
                    "status": "error",
                    "service": "gnosis-foil",
                    "transport": "flow-udp",
                    "reason": error,
                })),
            }
        }
        _ => compact_json(&serde_json::json!({
            "status": "ok",
            "service": "gnosis-foil",
            "transport": "flow-udp",
            "path": path,
        })),
    }
}

fn flow_probability_cache_key(
    path: &str,
    entropy_certificate: Option<&ResidentEntropyCertificate>,
) -> String {
    let route = path.split('?').next().unwrap_or(path);
    match route {
        "/.aeon/runtime-attestation" | "/.aeon/fano-xor" => {
            let entropy_fingerprint = entropy_certificate
                .map(|certificate| {
                    format!(
                        "{}:{}:{}:{}:{}:{}:{}",
                        certificate.kind,
                        certificate.version,
                        certificate.runtime,
                        certificate.host,
                        certificate.units_solved,
                        certificate.units_total,
                        certificate.elapsed_nanos
                    )
                })
                .unwrap_or_else(|| "none".to_string());
            format!("{path}#entropy={entropy_fingerprint}")
        }
        _ => path.to_string(),
    }
}

fn raw_capture_surface<'a>(
    cli: &'a Cli,
    certificate: &GnosisFoilRuntimeCertificate,
    backend: &'a GnosisFoilBackend,
) -> RawCaptureSurface<'a> {
    let raw_capture = backend.raw_capture.as_ref();
    RawCaptureSurface {
        service: "gnosis-foil",
        status: if certificate.raw_capture_attached {
            "attached"
        } else {
            "not-attached"
        },
        source: cli.raw_capture_jsonl.as_deref(),
        raw_capture_attached: certificate.raw_capture_attached,
        descriptor: raw_capture.map(|capture| &capture.descriptor),
        measured_latency_ns: raw_capture.and_then(|capture| capture.measured_latency_ns),
        captured_bytes: raw_capture.map(|capture| capture.bytes.len()).unwrap_or(0),
    }
}

fn resident_rf_fibonacci_report_for_url(
    url: &str,
    cli: &Cli,
    state: &Arc<Mutex<ResidentRfFibonacciState>>,
) -> Result<ResidentRfFibonacciReport, String> {
    let n = query_u32(url, "n", 20).min(93);
    let repetitions = query_u32(url, "repetitions", 100_000).clamp(1, 10_000_000);
    let retention_floor = u64::from(query_u32(
        url,
        "retention_floor",
        cli.smart_skip_retention_floor.min(u64::from(u32::MAX)) as u32,
    ));
    let kernel = match query_str(url, "kernel") {
        Some("adaptive") | Some("auto") | None => "adaptive",
        Some("fast") | Some("fast-doubling") | Some("doubling") => "fast-doubling",
        Some("rf") | Some("addition") | Some("rf-addition") => "rf-addition",
        Some("race") | Some("all") => "race",
        Some("smart") | Some("smart-skip") => "smart-skip",
        Some(other) => return Err(format!("unknown rf fibonacci kernel: {other}")),
    };
    let total_started = Instant::now();
    let mut state = state
        .lock()
        .map_err(|_| "resident RF Fibonacci state lock poisoned".to_string())?;
    state.request_count = state.request_count.saturating_add(1);
    let request_count = state.request_count;

    let observation_started = Instant::now();
    let (
        observation,
        input_source,
        engine_name,
        block_measured_latency_ns,
        captured_bytes,
        max_energy,
        mean_energy,
    ) = if let Some(engine) = state.raw_engine.as_mut() {
        let block = engine.capture_block_borrowed()?;
        let stats = GnosisFoilBackend::raw_block_stats(block.descriptor, block.bytes);
        let engine_kind = block.descriptor.engine_kind;
        let block_measured_latency_ns = block.measured_latency_ns;
        let observation = GnosisFoilBackend::observe_raw_stats(
            stats.byte_count,
            stats.witness_signal,
            cli.activation_threshold,
        );
        (
            observation,
            "resident-raw-device",
            match engine_kind {
                GnosisFoilEngineKind::RtlSdr => "rtl2832-bulk",
                GnosisFoilEngineKind::Wifi => "wifi",
                GnosisFoilEngineKind::Bluetooth => "bluetooth",
                GnosisFoilEngineKind::AmbientHost => "ambient-host",
                GnosisFoilEngineKind::Uring => "uring",
                GnosisFoilEngineKind::ChipsetRaw => "chipset-raw",
                GnosisFoilEngineKind::Synthetic => "synthetic",
                GnosisFoilEngineKind::EntropyGarden => "entropy-garden",
            },
            block_measured_latency_ns,
            stats.byte_count,
            Some(stats.max_energy),
            Some(stats.mean_energy),
        )
    } else if let Some(observation) = state.latest_r1_witness_observation {
        (
            observation,
            "resident-r1-btle-witness",
            "bluetooth",
            None,
            0,
            None,
            None,
        )
    } else {
        let backend = default_backend(cli);
        (
            backend.observation,
            "resident-synthetic-gate",
            "synthetic",
            None,
            0,
            None,
            None,
        )
    };
    let read_observation_ns = observation_started.elapsed().as_nanos();

    let cache_was_warm = (kernel == "smart-skip" || kernel == "adaptive")
        && state
            .cache
            .as_ref()
            .is_some_and(|cache| rf_fibonacci_cache_matches(n, &observation, cache));
    let compute_started = Instant::now();
    let (
        value,
        cache_hit_count,
        cache_miss_count,
        retained_witness_hits,
        recomputable_skips,
        addition_count,
        kernel_race,
    ) = match kernel {
        "adaptive" => {
            if let Some(cache) = state
                .cache
                .as_ref()
                .filter(|cache| rf_fibonacci_cache_matches(n, &observation, cache))
            {
                (
                    cache.value,
                    repetitions,
                    0,
                    cache.retained_witnesses.len(),
                    cache.recomputable_steps.len(),
                    cache.retained_witnesses.len(),
                    None,
                )
            } else if repetitions <= 16 {
                let measurement = fibonacci_fast_kernel_measurement(n, repetitions)?;
                (measurement.value, 0, 0, 0, 0, 0, None)
            } else {
                let result = rf_fibonacci_with_smart_skip_cache(
                    n,
                    &observation,
                    state.cache.as_ref(),
                    retention_floor,
                )?;
                let value = result.value;
                let retained_witness_hits = result.retained_witness_hits;
                let recomputable_skips = result.recomputable_skips;
                let addition_count = result.additions.len();
                state.cache = Some(result.cache);
                (
                    value,
                    repetitions.saturating_sub(1),
                    1,
                    retained_witness_hits,
                    recomputable_skips,
                    addition_count,
                    None,
                )
            }
        }
        "fast-doubling" => {
            let measurement = fibonacci_fast_kernel_measurement(n, repetitions)?;
            (measurement.value, 0, 0, 0, 0, 0, None)
        }
        "rf-addition" => {
            let mut value = 0;
            let mut addition_count = 0;
            for _ in 0..repetitions {
                let (next_value, additions) = rf_fibonacci(n, &observation)?;
                value = next_value;
                addition_count += additions.len();
            }
            (value, 0, repetitions, 0, 0, addition_count, None)
        }
        "smart-skip" => {
            if let Some(cache) = state
                .cache
                .as_ref()
                .filter(|cache| rf_fibonacci_cache_matches(n, &observation, cache))
            {
                (
                    cache.value,
                    repetitions,
                    0,
                    cache.retained_witnesses.len(),
                    cache.recomputable_steps.len(),
                    cache.retained_witnesses.len(),
                    None,
                )
            } else {
                let result = rf_fibonacci_with_smart_skip_cache(
                    n,
                    &observation,
                    state.cache.as_ref(),
                    retention_floor,
                )?;
                let value = result.value;
                let retained_witness_hits = result.retained_witness_hits;
                let recomputable_skips = result.recomputable_skips;
                let addition_count = result.additions.len();
                state.cache = Some(result.cache);
                (
                    value,
                    repetitions.saturating_sub(1),
                    1,
                    retained_witness_hits,
                    recomputable_skips,
                    addition_count,
                    None,
                )
            }
        }
        "race" => {
            let race_report = rf_fibonacci_race_all_kernels_with_resident_cache(
                n,
                &observation,
                repetitions,
                &mut state.cache,
                retention_floor,
                RaceLoserPolicy::from_env(),
            )?;
            (
                race_report.value,
                race_report.cache_hit_count,
                race_report.cache_miss_count,
                race_report.retained_witness_hits,
                race_report.recomputable_skips,
                race_report.rf_addition_count,
                Some(race_report),
            )
        }
        _ => unreachable!("kernel query validated above"),
    };
    let compute_ns = compute_started.elapsed().as_nanos();
    let cache_warm_after = (kernel == "smart-skip" || kernel == "race" || kernel == "adaptive")
        && state
            .cache
            .as_ref()
            .is_some_and(|cache| rf_fibonacci_cache_matches(n, &observation, cache));
    let retained_witness_count = state
        .cache
        .as_ref()
        .map(|cache| cache.retained_witnesses.len())
        .unwrap_or(0);
    let recomputable_step_count = state
        .cache
        .as_ref()
        .map(|cache| cache.recomputable_steps.len())
        .unwrap_or(0);
    let shape_key = state.cache.as_ref().map(|cache| cache.shape_key.clone());
    let expected = expected_fibonacci(n);

    Ok(ResidentRfFibonacciReport {
        status: "ok",
        service: "gnosis-foil",
        endpoint: "/.aeon/rf-fibonacci",
        n,
        repetitions,
        value,
        expected,
        verified: expected == Some(value),
        input_source,
        engine: engine_name,
        kernel,
        resident_request_count: request_count,
        cache_was_warm,
        cache_warm_after,
        cache_hit_count,
        cache_miss_count,
        retained_witness_hits,
        recomputable_skips,
        addition_count,
        retained_witness_count,
        recomputable_step_count,
        read_observation_ns,
        compute_ns,
        total_ns: total_started.elapsed().as_nanos(),
        block_measured_latency_ns,
        captured_bytes,
        max_energy,
        mean_energy,
        witness_signal: observation.gate.witness_signal,
        selected_channels: observation.projection.selected_channels,
        race_candidate_count: observation.projection.race_candidate_count,
        shape_key,
        kernel_race,
    })
}

fn resident_rf_fibonacci_report(
    request: &Request,
    cli: &Cli,
    state: &Arc<Mutex<ResidentRfFibonacciState>>,
) -> Result<ResidentRfFibonacciReport, String> {
    resident_rf_fibonacci_report_for_url(request.url(), cli, state)
}

fn resident_rf_fibonacci_witness_bench_for_url(
    url: &str,
    cli: &Cli,
    state: &Arc<Mutex<ResidentRfFibonacciState>>,
) -> Result<ResidentRfFibonacciWitnessBenchReport, String> {
    let n = query_u32(url, "n", 20).min(93);
    let repetitions = query_u32(url, "repetitions", 100_000).clamp(17, 10_000_000);
    let cold_url =
        format!("/.aeon/rf-fibonacci?n={n}&repetitions={repetitions}&kernel=fast-doubling");
    let witness_url =
        format!("/.aeon/rf-fibonacci?n={n}&repetitions={repetitions}&kernel=adaptive");
    let witness_observation = state
        .lock()
        .map_err(|_| "resident RF Fibonacci state lock poisoned".to_string())?
        .latest_r1_witness_observation;
    let cold_synthetic_state = resident_rf_fibonacci_state_for_observation(None);
    let cold_synthetic =
        resident_rf_fibonacci_report_for_url(&cold_url, cli, &cold_synthetic_state)?;

    let (witness_first, witness_reuse) = if let Some(observation) = witness_observation {
        let witness_state = resident_rf_fibonacci_state_for_observation(Some(observation));
        let first = resident_rf_fibonacci_report_for_url(&witness_url, cli, &witness_state)?;
        let reuse = resident_rf_fibonacci_report_for_url(&witness_url, cli, &witness_state)?;
        (Some(first), Some(reuse))
    } else {
        (None, None)
    };
    let cache_hit_delta = witness_reuse
        .as_ref()
        .map(|report| i64::from(report.cache_hit_count) - i64::from(cold_synthetic.cache_hit_count))
        .unwrap_or(0);
    let selected_channel_delta = witness_reuse
        .as_ref()
        .map(|report| {
            i64::from(report.selected_channels) - i64::from(cold_synthetic.selected_channels)
        })
        .unwrap_or(0);
    let witness_reuse_compute_ns_delta = witness_reuse
        .as_ref()
        .map(|report| report.compute_ns as i128 - cold_synthetic.compute_ns as i128)
        .unwrap_or(0);

    Ok(ResidentRfFibonacciWitnessBenchReport {
        status: "ok",
        service: "gnosis-foil",
        endpoint: "/.aeon/rf-fibonacci-witness-bench",
        n,
        repetitions,
        witness_available: witness_observation.is_some(),
        interpretation: "R1 BTLE witnesses admit/diversify the deterministic RF Fibonacci path; cache hits measure resident reuse, not external compute.",
        cold_synthetic,
        witness_first,
        witness_reuse,
        cache_hit_delta,
        selected_channel_delta,
        witness_reuse_compute_ns_delta,
    })
}

struct FlowWork {
    peer: SocketAddr,
    frame: FoilFlowFrame,
}

struct FlowProbabilityRuntime {
    enabled: bool,
    policy: MeshProbabilityPolicy,
    admission: Mutex<MeshProbabilityAdmission<Vec<u8>>>,
    reuse_decisions: AtomicU64,
    speculate_decisions: AtomicU64,
    cover_decisions: AtomicU64,
    explore_decisions: AtomicU64,
    admitted_cached_responses: AtomicU64,
    lock_misses: AtomicU64,
}

impl FlowProbabilityRuntime {
    fn new(enabled: bool, policy: MeshProbabilityPolicy) -> Self {
        Self {
            enabled,
            policy,
            admission: Mutex::new(MeshProbabilityAdmission::<Vec<u8>>::new(policy)),
            reuse_decisions: AtomicU64::new(0),
            speculate_decisions: AtomicU64::new(0),
            cover_decisions: AtomicU64::new(0),
            explore_decisions: AtomicU64::new(0),
            admitted_cached_responses: AtomicU64::new(0),
            lock_misses: AtomicU64::new(0),
        }
    }

    fn record_decision(&self, decision: MeshProbabilityDecision) {
        match decision {
            MeshProbabilityDecision::Reuse => {
                self.reuse_decisions.fetch_add(1, Ordering::Relaxed);
            }
            MeshProbabilityDecision::Speculate => {
                self.speculate_decisions.fetch_add(1, Ordering::Relaxed);
            }
            MeshProbabilityDecision::Cover => {
                self.cover_decisions.fetch_add(1, Ordering::Relaxed);
            }
            MeshProbabilityDecision::Explore => {
                self.explore_decisions.fetch_add(1, Ordering::Relaxed);
            }
        }
    }

    fn record_admitted_cached_response(&self) {
        self.admitted_cached_responses
            .fetch_add(1, Ordering::Relaxed);
    }

    fn record_lock_miss(&self) {
        self.lock_misses.fetch_add(1, Ordering::Relaxed);
    }

    fn surface(&self) -> FlowProbabilitySurface {
        let (observations, tracked_keys) = match self.admission.lock() {
            Ok(admission) => (admission.total_mass(), admission.len()),
            Err(_) => {
                self.record_lock_miss();
                (0, 0)
            }
        };

        FlowProbabilitySurface {
            status: if self.enabled {
                "default-on"
            } else {
                "disabled"
            },
            policy: MeshProbabilityPolicySurface {
                min_observations: self.policy.min_observations,
                min_concentration_bps: self.policy.min_concentration_bps,
                residual_budget: self.policy.residual_budget,
                max_entries: self.policy.max_entries,
            },
            observations,
            tracked_keys,
            reuse_decisions: self.reuse_decisions.load(Ordering::Relaxed),
            speculate_decisions: self.speculate_decisions.load(Ordering::Relaxed),
            cover_decisions: self.cover_decisions.load(Ordering::Relaxed),
            explore_decisions: self.explore_decisions.load(Ordering::Relaxed),
            admitted_cached_responses: self.admitted_cached_responses.load(Ordering::Relaxed),
            lock_misses: self.lock_misses.load(Ordering::Relaxed),
        }
    }
}

type FlowProbabilityRuntimeRef = Arc<FlowProbabilityRuntime>;

enum FlowWireResponse {
    Frame(FoilFlowFrame),
    FixedFanoXor([u8; distributed_inference::gnosis_foil::FANO_XOR_FLOW_PACKED_ROUTE_FRAME_SIZE]),
}

#[cfg(test)]
impl FlowWireResponse {
    fn to_frame(&self) -> Result<FoilFlowFrame, String> {
        match self {
            Self::Frame(frame) => Ok(frame.clone()),
            Self::FixedFanoXor(bytes) => FoilFlowFrame::decode(bytes),
        }
    }
}

#[cfg(test)]
fn flow_response_for_frame(
    frame: FoilFlowFrame,
    certificate: &GnosisFoilRuntimeCertificate,
    entropy_certificate: Option<&ResidentEntropyCertificate>,
    cli: &Cli,
    resident_rf_fibonacci: &Arc<Mutex<ResidentRfFibonacciState>>,
    resident_model_forward_cache: &Arc<Mutex<ResidentModelForwardCacheState>>,
    probability_runtime: &FlowProbabilityRuntime,
) -> Option<FoilFlowFrame> {
    flow_wire_response_for_frame(
        frame,
        certificate,
        entropy_certificate,
        cli,
        resident_rf_fibonacci,
        resident_model_forward_cache,
        probability_runtime,
    )
    .and_then(|response| response.to_frame().ok())
}

fn flow_wire_response_for_frame(
    frame: FoilFlowFrame,
    certificate: &GnosisFoilRuntimeCertificate,
    entropy_certificate: Option<&ResidentEntropyCertificate>,
    cli: &Cli,
    resident_rf_fibonacci: &Arc<Mutex<ResidentRfFibonacciState>>,
    resident_model_forward_cache: &Arc<Mutex<ResidentModelForwardCacheState>>,
    probability_runtime: &FlowProbabilityRuntime,
) -> Option<FlowWireResponse> {
    let Some(path) = parse_flow_path(&frame.payload) else {
        let payload = compact_json(&serde_json::json!({
            "status": "bad_request",
            "service": "gnosis-foil",
            "reason": "Flow payload must be a raw path or GET envelope",
        }));
        return Some(FlowWireResponse::Frame(FoilFlowFrame {
            stream_id: frame.stream_id,
            sequence: frame.sequence,
            flags: URING_FLOW_FIN | URING_FLOW_VENT,
            payload,
        }));
    };

    if path.split('?').next().unwrap_or(path.as_str()) == "/.aeon/fano-xor.bytes" {
        return Some(FlowWireResponse::FixedFanoXor(
            fano_xor_flow_packed_route_frame(
                frame.stream_id,
                frame.sequence,
                URING_FLOW_FIN,
                certificate,
            ),
        ));
    }

    let cache_key = flow_probability_cache_key(&path, entropy_certificate);
    let mut ehla_harvested = false;
    let mut _ehla_debt = 0;

    if probability_runtime.enabled {
        if let Ok(mut admission) = probability_runtime.admission.lock() {
            let witness = admission.observe(cache_key.clone());
            probability_runtime.record_decision(witness.decision);

            // EHLA Hotpath: if enabled and debt is low, harvest the gap.
            if cli.ehla_enabled && admission.interpretation_debt() < cli.ehla_max_debt {
                admission.increment_debt();
                ehla_harvested = true;
                _ehla_debt = admission.interpretation_debt();
            } else if let Some(payload) = admission.get_admitted_cached(&witness) {
                probability_runtime.record_admitted_cached_response();
                return Some(FlowWireResponse::Frame(FoilFlowFrame {
                    stream_id: frame.stream_id,
                    sequence: frame.sequence,
                    flags: URING_FLOW_FIN,
                    payload,
                }));
            }
        } else {
            probability_runtime.record_lock_miss();
        }
    }

    let payload = flow_payload_for_path(
        &path,
        certificate,
        entropy_certificate,
        cli,
        resident_rf_fibonacci,
        resident_model_forward_cache,
    );

    if probability_runtime.enabled {
        if let Ok(mut admission) = probability_runtime.admission.lock() {
            if ehla_harvested {
                // Background resolution simulation: remember without blocking the response.
                admission.remember_latent(&cache_key, payload.clone());
            } else {
                admission.remember(&cache_key, payload.clone());
            }
        } else {
            probability_runtime.record_lock_miss();
        }
    }

    Some(FlowWireResponse::Frame(FoilFlowFrame {
        stream_id: frame.stream_id,
        sequence: frame.sequence,
        flags: if ehla_harvested {
            URING_FLOW_FIN | 0x80
        } else {
            URING_FLOW_FIN
        }, // 0x80 = EHLA_HARVESTED
        payload,
    }))
}

fn spawn_flow_listener(
    cli: &Cli,
    certificate: Arc<GnosisFoilRuntimeCertificate>,
    entropy_certificate: Option<ResidentEntropyCertificate>,
    resident_rf_fibonacci: Arc<Mutex<ResidentRfFibonacciState>>,
    resident_model_forward_cache: Arc<Mutex<ResidentModelForwardCacheState>>,
    probability_runtime: FlowProbabilityRuntimeRef,
) -> Result<Option<thread::JoinHandle<()>>, Box<dyn std::error::Error + Send + Sync>> {
    if !cli.flow_enabled {
        return Ok(None);
    }

    let bind = format!("{}:{}", cli.host, cli.flow_port);
    let socket = UdpSocket::bind(&bind)?;
    let socket = Arc::new(socket);
    eprintln!(
        "gnosis-foil-control Flow/UDP listening on aeon://{bind} with {} worker(s)",
        cli.flow_workers
    );
    let flow_cli = cli.clone();
    let (sender, receiver) = mpsc::sync_channel::<FlowWork>(cli.flow_workers.saturating_mul(256));
    let receiver = Arc::new(Mutex::new(receiver));

    for _worker_index in 0..cli.flow_workers {
        let worker_socket = Arc::clone(&socket);
        let worker_receiver = Arc::clone(&receiver);
        let worker_certificate = Arc::clone(&certificate);
        let worker_entropy_certificate = entropy_certificate.clone();
        let worker_cli = flow_cli.clone();
        let worker_resident_rf_fibonacci = Arc::clone(&resident_rf_fibonacci);
        let worker_resident_model_forward_cache = Arc::clone(&resident_model_forward_cache);
        let worker_probability_runtime = Arc::clone(&probability_runtime);
        thread::spawn(move || loop {
            let work = {
                let Ok(receiver) = worker_receiver.lock() else {
                    break;
                };
                receiver.recv()
            };
            let Ok(work) = work else {
                break;
            };
            let Some(response) = flow_wire_response_for_frame(
                work.frame,
                &worker_certificate,
                worker_entropy_certificate.as_ref(),
                &worker_cli,
                &worker_resident_rf_fibonacci,
                &worker_resident_model_forward_cache,
                &worker_probability_runtime,
            ) else {
                continue;
            };
            match response {
                FlowWireResponse::Frame(frame) => {
                    if let Ok(bytes) = frame.encode() {
                        let _ = worker_socket.send_to(&bytes, work.peer);
                    }
                }
                FlowWireResponse::FixedFanoXor(bytes) => {
                    let _ = worker_socket.send_to(&bytes, work.peer);
                }
            }
        });
    }

    Ok(Some(thread::spawn(move || {
        let mut buffer = vec![0_u8; 65_536];
        loop {
            let Ok((len, peer)) = socket.recv_from(&mut buffer) else {
                continue;
            };
            let Ok(frame) = FoilFlowFrame::decode(&buffer[..len]) else {
                continue;
            };
            if sender.send(FlowWork { peer, frame }).is_err() {
                break;
            }
        }
    })))
}

fn handle_get(
    request: &Request,
    cli: &Cli,
    backend: &GnosisFoilBackend,
    certificate: &GnosisFoilRuntimeCertificate,
    entropy_certificate: Option<&ResidentEntropyCertificate>,
    resident_rf_fibonacci: &Arc<Mutex<ResidentRfFibonacciState>>,
    resident_model_forward_cache: &Arc<Mutex<ResidentModelForwardCacheState>>,
    probability_runtime: &FlowProbabilityRuntime,
) -> Response<std::io::Cursor<Vec<u8>>> {
    let route = request.url().split('?').next().unwrap_or("/");
    let origin = origin(request, cli);
    match route {
        "/" | "/.aeon/health" => json_response(
            &HealthSurface {
                status: "ok",
                service: "gnosis-foil",
                runtime: "gnosis",
                host: "gnosis-foil",
                capabilities: vec![
                    "aeon-control-surface",
                    "flow-udp-control-surface",
                    "foil-runtime-certificate",
                    "protocol69-envelope-validation",
                    "flowframe-10-byte",
                    "radio-witness-gate",
                    "uring-race-baseline",
                    "resident-rf-fibonacci-smart-skip",
                    "resident-model-forward-cache",
                    "machine-number-fast-path-certificates",
                    "ditto-runtime-replacement-fallback",
                    "protocol69-workflow-dispatch",
                    "protocol69-antiqueue-network-dispatch",
                ],
                fano_xor: runtime_attestation_summary(certificate, entropy_certificate),
                certificate,
                timestamp_ms: now_ms(),
            },
            StatusCode(200),
        ),
        "/.aeon/session" | "/.aeon/capabilities" => json_response(
            &SessionSurface {
                service: "gnosis-foil",
                topology: TopologySurface {
                    mode: "radio-witness-control",
                    semantic_boundary: "rf-ingress-flowframe-fold",
                },
                transports: TransportSurface {
                    http: EndpointSurface {
                        endpoint: Some(origin.clone()),
                        status: "available",
                        description: "Native gnosis-foil HTTP control listener.",
                    },
                    raw_flow: flow_endpoint(request, cli),
                    radio_witness: EndpointSurface {
                        endpoint: None,
                        status: "library-ready",
                        description: "RTL-SDR raw bytes, projected waterfall frames, Wi-Fi witnesses, and Bluetooth witnesses are represented by the library contract.",
                    },
                    loopback_proxy: loopback_proxy_endpoint(cli),
                },
                surfaces: SurfaceStatus {
                    control: "native",
                    app: if cli.proxy_upstream.is_some() {
                        "loopback-proxy"
                    } else {
                        "unavailable"
                    },
                    gnode: if cli.gnode_enabled && cli.proxy_upstream.is_some() {
                        "front-owned-loopback-bridge"
                    } else {
                        "unavailable"
                    },
                    wasm: if cli.wasm_enabled && cli.proxy_upstream.is_some() {
                        "front-owned-loopback-bridge"
                    } else {
                        "unavailable"
                    },
                    braid_benchmark: "native",
                },
                fallback_chain: if cli.proxy_upstream.is_some() {
                    vec!["native-control", "loopback-proxy", "flow-udp"]
                } else {
                    vec!["flow-udp"]
                },
                fano_xor: runtime_attestation_summary(certificate, entropy_certificate),
                certificate,
            },
            StatusCode(200),
        ),
        "/.aeon/flow" | "/.aeon/udp" => json_response(
            &FlowSurface {
                service: "gnosis-foil",
                transport: "flow-udp",
                frame_header_bytes: distributed_inference::gnosis_foil::FLOW_HEADER_SIZE,
                endpoint: flow_endpoint(request, cli),
                compatible_with: "gnosis-uring",
                probability_admission: probability_runtime.surface(),
                fano_xor: runtime_attestation_summary(certificate, entropy_certificate),
                certificate,
            },
            StatusCode(200),
        ),
        "/.aeon/protocol69" => json_response(
            &serde_json::json!({
                "status": "ok",
                "service": "gnosis-foil",
                "transport": "http",
                "projection": build_protocol69_projection_envelope(),
            }),
            StatusCode(200),
        ),
        "/.aeon/fano-xor.bytes" => binary_response(
            fano_xor_flow_bytes(certificate),
            StatusCode(200),
            "application/vnd.gnosis.fano-xor-route",
        ),
        "/.aeon/raw-capture" => json_response(
            &raw_capture_surface(cli, certificate, backend),
            StatusCode(200),
        ),
        "/.aeon/runtime-attestation" => json_response(
            &RuntimeAttestationSurface {
                source: "gnosis-foil-control",
                transport: "http",
                attestation: certificate,
                async_loser_queue_telemetry_theorem_ids:
                    foil_async_loser_queue_telemetry_theorem_ids(),
                summary: runtime_attestation_summary(certificate, entropy_certificate),
                entropy_certificate,
            },
            StatusCode(200),
        ),
        "/.aeon/entropy-attestation" => match entropy_certificate {
            Some(entropy_certificate) => json_response(entropy_certificate, StatusCode(200)),
            None => json_response(
                &serde_json::json!({
                    "status": "unavailable",
                    "service": "gnosis-foil",
                    "reason": "no entropy-harvest-jsonl source configured",
                }),
                StatusCode(404),
            ),
        },
        "/.aeon/r1-phyle-entropy" => match r1_phyle_entropy_surface_for_url(request.url()) {
            Ok(surface) => compact_json_response(&surface, StatusCode(200)),
            Err(error) => bad_request(&error),
        },
        "/.aeon/protocol69/workflow/seed" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": PROTOCOL69_WORKFLOW_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/protocol69/workflow/claim" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/protocol69/workflow/ack" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contracts": [
                    PROTOCOL69_INPUT_ACK_CONTRACT_ID,
                    PROTOCOL69_LAZY_ACK_CONTRACT_ID,
                ],
            }),
            StatusCode(405),
        ),
        "/.aeon/protocol69/network/seed" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": PROTOCOL69_WORKFLOW_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/protocol69/network/claim" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": PROTOCOL69_DISPATCH_CLAIM_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/protocol69/network/ack" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contracts": [
                    PROTOCOL69_INPUT_ACK_CONTRACT_ID,
                    PROTOCOL69_LAZY_ACK_CONTRACT_ID,
                ],
            }),
            StatusCode(405),
        ),
        "/.aeon/r1-worksteal" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": R1_WORKSTEAL_HINT_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/r1-worksteal/seed" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": R1_WORKSTEAL_HINT_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/r1-worksteal/receipt" => json_response(
            &serde_json::json!({
                "status": "method_required",
                "service": "gnosis-foil",
                "method": "POST",
                "contract": R1_WORKSTEAL_RECEIPT_SUBMISSION_CONTRACT_ID,
            }),
            StatusCode(405),
        ),
        "/.aeon/braid-collapse-bench" => json_response(
            &braid_benchmark_report(request, certificate),
            StatusCode(200),
        ),
        "/.aeon/rf-fibonacci-witness-bench" => match resident_rf_fibonacci_witness_bench_for_url(
            request.url(),
            cli,
            resident_rf_fibonacci,
        ) {
            Ok(report) => compact_json_response(&report, StatusCode(200)),
            Err(error) => internal_error(&error),
        },
        route if is_rf_fibonacci_route(route) => match resident_rf_fibonacci_report(request, cli, resident_rf_fibonacci) {
            Ok(report) => match query_str(request.url(), "format") {
                Some("bwf2") | Some("binary") => binary_response(
                    ResidentRfFibonacciBinaryReport::from_report(&report)
                        .to_bytes()
                        .to_vec(),
                    StatusCode(200),
                    "application/vnd.gnosis.bwf2",
                ),
                _ => compact_json_response(&report, StatusCode(200)),
            },
            Err(error) => internal_error(&error),
        },
        route if is_model_forward_cache_route(route) => {
            match resident_model_forward_cache_report_for_url(
                request.url(),
                resident_model_forward_cache,
            ) {
                Ok(report) => compact_json_response(&report, StatusCode(200)),
                Err(error) => bad_request(&error),
            }
        }
        _ => not_found(),
    }
}

fn should_handle_native(route: &str, proxy_enabled: bool) -> bool {
    (!proxy_enabled && route == "/")
        || matches!(
            route,
            "/.aeon/health"
                | "/.aeon/session"
                | "/.aeon/capabilities"
                | "/.aeon/flow"
                | "/.aeon/udp"
                | "/.aeon/protocol69"
                | "/.aeon/protocol69/workflow/seed"
                | "/.aeon/protocol69/workflow/claim"
                | "/.aeon/protocol69/workflow/ack"
                | "/.aeon/protocol69/network/seed"
                | "/.aeon/protocol69/network/claim"
                | "/.aeon/protocol69/network/ack"
                | "/.aeon/r1-witness"
                | "/.aeon/r1-worksteal"
                | "/.aeon/r1-worksteal/seed"
                | "/.aeon/r1-worksteal/claim"
                | "/.aeon/r1-worksteal/receipt"
                | "/.aeon/fano-xor.bytes"
                | "/.aeon/raw-capture"
                | "/.aeon/runtime-attestation"
                | "/.aeon/entropy-attestation"
                | "/.aeon/r1-phyle-entropy"
                | "/.aeon/braid-collapse-bench"
                | "/.aeon/rf-fibonacci-witness-bench"
                | "/.aeon/ditto/replace"
        )
        || is_rf_fibonacci_route(route)
        || is_model_forward_cache_route(route)
}

fn validate_protocol69_body(body: &[u8]) -> Result<Protocol69ProjectionEnvelope, String> {
    let envelope: Protocol69ProjectionEnvelope = serde_json::from_slice(body)
        .map_err(|error| format!("invalid protocol69 envelope: {error}"))?;
    validate_protocol69_projection_envelope(&envelope)?;
    Ok(envelope)
}

fn validate_r1_foil_witness_report(report: &R1FoilWitnessReport) -> Result<(), String> {
    if report.schema_version != R1_FOIL_WITNESS_SCHEMA_VERSION {
        return Err("schemaVersion mismatch".to_string());
    }
    if report.contract_id != R1_FOIL_WITNESS_CONTRACT_ID {
        return Err("contractId mismatch".to_string());
    }
    if report.ingress != "BluetoothChannelWitness" {
        return Err("ingress must be BluetoothChannelWitness".to_string());
    }
    if report.theorem_id != R1_FOIL_WITNESS_THEOREM_ID {
        return Err("theoremId mismatch".to_string());
    }
    if report.device_id.trim().is_empty() {
        return Err("deviceId must be nonempty".to_string());
    }
    if !(-127..=20).contains(&report.rssi_dbm) {
        return Err("rssiDbm must be in [-127, 20]".to_string());
    }
    validate_protocol69_projection_envelope(&report.projection)?;
    Ok(())
}

fn parse_r1_foil_witness_reports(body: &[u8]) -> Result<Vec<R1FoilWitnessReport>, String> {
    let post_body: R1FoilWitnessPostBody = serde_json::from_slice(body)
        .map_err(|error| format!("invalid R1 witness body: {error}"))?;
    let reports = match post_body {
        R1FoilWitnessPostBody::Single(report) => vec![report],
        R1FoilWitnessPostBody::Batch(reports) => reports,
    };
    if reports.is_empty() {
        return Err("R1 witness batch must not be empty".to_string());
    }
    if reports.len() > R1_FOIL_WITNESS_BATCH_LIMIT {
        return Err(format!(
            "R1 witness batch exceeds limit {R1_FOIL_WITNESS_BATCH_LIMIT}"
        ));
    }
    for report in &reports {
        validate_r1_foil_witness_report(report)?;
    }
    Ok(reports)
}

fn r1_reports_to_channel_witnesses(
    reports: &[R1FoilWitnessReport],
) -> Vec<GnosisFoilChannelWitness> {
    reports
        .iter()
        .map(|report| GnosisFoilChannelWitness {
            ingress: GnosisFoilIngress::BluetoothChannelWitness,
            channel_id: report.channel_id,
            frequency_hz: None,
            rssi_dbm: Some(report.rssi_dbm),
            packet_seen: report.packet_seen,
            cadence_ms: report.cadence_ms,
        })
        .collect()
}

fn r1_witness_backend(
    reports: &[R1FoilWitnessReport],
    activation_threshold: u16,
) -> GnosisFoilBackend {
    GnosisFoilBackend::from_channel_witnesses(
        GnosisFoilIngress::BluetoothChannelWitness,
        r1_reports_to_channel_witnesses(reports),
        activation_threshold,
    )
}

fn apply_r1_witness_reports_to_resident_fibonacci_state(
    reports: &[R1FoilWitnessReport],
    activation_threshold: u16,
    state: &Arc<Mutex<ResidentRfFibonacciState>>,
) -> Result<GnosisFoilBackend, String> {
    let witness_backend = r1_witness_backend(reports, activation_threshold);
    let mut state = state
        .lock()
        .map_err(|_| "resident RF Fibonacci state lock poisoned".to_string())?;
    let previous_shape = state.latest_r1_witness_observation.map(|observation| {
        distributed_inference::gnosis_foil::rf_fibonacci_shape_parts(&observation)
    });
    let next_shape =
        distributed_inference::gnosis_foil::rf_fibonacci_shape_parts(&witness_backend.observation);

    state.latest_r1_witness_observation = Some(witness_backend.observation);
    state.binary_response_cache.clear();
    if previous_shape != Some(next_shape) {
        state.cache = None;
    }

    Ok(witness_backend)
}

fn validate_ditto_replacement_packet(body: &[u8]) -> Result<DittoReplacementPacket, String> {
    let packet: DittoReplacementPacket =
        serde_json::from_slice(body).map_err(|error| format!("invalid ditto packet: {error}"))?;
    match packet.mode.as_str() {
        "monster-cannon" | "monster-resident" => {}
        other => return Err(format!("unsupported ditto replacement mode: {other}")),
    }
    match packet.unit_of_work.as_str() {
        "topology-round" | "request" => {}
        other => return Err(format!("unsupported ditto unit of work: {other}")),
    }
    if packet.source_path.trim().is_empty() {
        return Err("ditto sourcePath is required".to_string());
    }
    if packet.http.method.trim().is_empty() {
        return Err("ditto http.method is required".to_string());
    }
    if !packet.http.path.starts_with('/') {
        return Err("ditto http.path must be absolute".to_string());
    }
    if let Some(body) = packet.http.body.as_ref() {
        if body.encoding != "base64" {
            return Err("ditto http.body encoding must be base64".to_string());
        }
        if BASE64_STANDARD.decode(&body.value).is_err() {
            return Err("ditto http.body base64 payload is invalid".to_string());
        }
    }
    Ok(packet)
}

fn no_content() -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_data(Vec::new())
        .with_status_code(StatusCode(204))
        .with_header(Header::from_bytes("Cache-Control", "no-store").expect("header"))
        .with_header(Header::from_bytes("X-Aeon-Native", "gnosis-foil").expect("header"))
}

