fn handle_r1_witness_post(
    request: &mut Request,
    activation_threshold: u16,
    resident_rf_fibonacci: &Arc<Mutex<ResidentRfFibonacciState>>,
) -> Response<std::io::Cursor<Vec<u8>>> {
    let mut body = Vec::new();
    match request.as_reader().read_to_end(&mut body) {
        Ok(_) => match parse_r1_foil_witness_reports(&body) {
            Ok(reports) => {
                match apply_r1_witness_reports_to_resident_fibonacci_state(
                    &reports,
                    activation_threshold,
                    resident_rf_fibonacci,
                ) {
                    Ok(witness_backend) => {
                        let certificate = witness_backend.runtime_certificate();
                        let response = R1FoilWitnessAdmissionResponse {
                            status: "accepted",
                            service: "gnosis-foil",
                            transport: "http",
                            accepted: true,
                            witness_count: reports.len(),
                            protocol69_accepted: true,
                            summary: runtime_attestation_summary(&certificate, None),
                            attestation: certificate,
                            reports: &reports,
                        };
                        compact_json_response(&response, StatusCode(200))
                    }
                    Err(error) => compact_json_response(
                        &serde_json::json!({
                            "status": "rejected",
                            "service": "gnosis-foil",
                            "reason": error,
                        }),
                        StatusCode(500),
                    ),
                }
            }
            Err(error) => compact_json_response(
                &serde_json::json!({
                    "status": "rejected",
                    "service": "gnosis-foil",
                    "reason": error,
                }),
                StatusCode(400),
            ),
        },
        Err(error) => bad_request(&format!("failed to read R1 witness body: {error}")),
    }
}

