fn handle_ditto_replacement_post(request: &mut Request) -> Response<std::io::Cursor<Vec<u8>>> {
    let dry_run = matches!(query_str(request.url(), "mode"), Some("dry-run"));
    let body = match read_proxy_body(request) {
        Ok(body) => body,
        Err(_) => return bad_request("failed to read ditto replacement body"),
    };
    match validate_ditto_replacement_packet(&body) {
        Ok(packet) => {
            let _ = (packet.http.query.as_deref(), packet.http.headers.len());
            if dry_run {
                return compact_json_response(
                    &ditto_replacement_dry_run_response(&packet),
                    StatusCode(200),
                );
            }
            no_content()
        }
        Err(error) => bad_request(&error),
    }
}

fn read_proxy_body(request: &mut Request) -> io::Result<Vec<u8>> {
    let content_length = request
        .headers()
        .iter()
        .find(|header| header.field.equiv("Content-Length"))
        .and_then(|header| header.value.as_str().parse::<usize>().ok())
        .unwrap_or(0);
    let mut body = Vec::with_capacity(content_length);
    if content_length > 0 {
        request
            .as_reader()
            .take(content_length as u64)
            .read_to_end(&mut body)?;
    }
    Ok(body)
}

fn proxy_request(
    request: &mut Request,
    upstream: &ProxyUpstream,
) -> Response<std::io::Cursor<Vec<u8>>> {
    let body = match read_proxy_body(request) {
        Ok(body) => body,
        Err(_) => return bad_gateway("failed to read request body for loopback proxy"),
    };
    let method = request.method().as_str();
    let mut forwarded = Vec::<u8>::new();
    let _ = write!(
        forwarded,
        "{method} {} HTTP/1.1\r\nHost: {}:{}\r\nConnection: close\r\n",
        request.url(),
        upstream.host,
        upstream.port
    );
    for header in request.headers() {
        if header.field.equiv("Host")
            || header.field.equiv("Connection")
            || header.field.equiv("Content-Length")
        {
            continue;
        }
        let _ = write!(
            forwarded,
            "{}: {}\r\n",
            header.field.as_str(),
            header.value.as_str()
        );
    }
    if !body.is_empty() {
        let _ = write!(forwarded, "Content-Length: {}\r\n", body.len());
    }
    forwarded.extend_from_slice(b"\r\n");
    forwarded.extend_from_slice(&body);

    let mut stream = match TcpStream::connect((upstream.host.as_str(), upstream.port)) {
        Ok(stream) => stream,
        Err(_) => return bad_gateway("loopback proxy upstream refused connection"),
    };
    let _ = stream.set_nodelay(true);
    let _ = stream.set_read_timeout(Some(Duration::from_millis(500)));
    if stream.write_all(&forwarded).is_err() {
        return bad_gateway("failed to write request to loopback proxy upstream");
    }

    let raw_response = match read_proxy_response(stream) {
        Ok(response) => response,
        Err(_) => return bad_gateway("failed to read response from loopback proxy upstream"),
    };

    proxy_response_from_raw(raw_response)
}

fn read_proxy_response(stream: TcpStream) -> io::Result<Vec<u8>> {
    let mut reader = BufReader::new(stream);
    let mut raw_response = Vec::<u8>::new();
    loop {
        let mut line = Vec::<u8>::new();
        let bytes_read = reader.read_until(b'\n', &mut line)?;
        if bytes_read == 0 {
            break;
        }
        raw_response.extend_from_slice(&line);
        if line == b"\r\n" || line == b"\n" {
            break;
        }
    }

    let Some(header_end) = raw_response
        .windows(4)
        .position(|window| window == b"\r\n\r\n")
    else {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "missing upstream response header terminator",
        ));
    };
    let header_bytes = &raw_response[..header_end];
    let header_text = std::str::from_utf8(header_bytes)
        .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
    let content_length = header_text
        .lines()
        .filter_map(|line| line.split_once(':'))
        .find(|(name, _)| name.eq_ignore_ascii_case("content-length"))
        .and_then(|(_, value)| value.trim().parse::<usize>().ok())
        .unwrap_or(0);
    let transfer_encoding_chunked = header_text
        .lines()
        .filter_map(|line| line.split_once(':'))
        .any(|(name, value)| {
            name.eq_ignore_ascii_case("transfer-encoding")
                && value
                    .split(',')
                    .any(|encoding| encoding.trim().eq_ignore_ascii_case("chunked"))
        });
    if content_length > 0 {
        let mut body = vec![0_u8; content_length];
        reader.read_exact(&mut body)?;
        raw_response.extend_from_slice(&body);
    } else if transfer_encoding_chunked {
        let mut decoded_body = Vec::<u8>::new();
        loop {
            let mut size_line = String::new();
            reader.read_line(&mut size_line)?;
            let size_text = size_line
                .split_once(';')
                .map(|(size, _)| size)
                .unwrap_or(size_line.as_str())
                .trim();
            let chunk_size = usize::from_str_radix(size_text, 16).map_err(|error| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    format!("invalid chunk size '{size_text}': {error}"),
                )
            })?;
            if chunk_size == 0 {
                let mut trailer_line = String::new();
                loop {
                    trailer_line.clear();
                    reader.read_line(&mut trailer_line)?;
                    if trailer_line == "\r\n" || trailer_line == "\n" || trailer_line.is_empty() {
                        break;
                    }
                }
                break;
            }
            let mut chunk = vec![0_u8; chunk_size];
            reader.read_exact(&mut chunk)?;
            decoded_body.extend_from_slice(&chunk);
            let mut crlf = [0_u8; 2];
            reader.read_exact(&mut crlf)?;
        }
        raw_response.extend_from_slice(&decoded_body);
    } else {
        let mut body = Vec::<u8>::new();
        let mut buffer = [0_u8; 4096];
        loop {
            match reader.read(&mut buffer) {
                Ok(0) => break,
                Ok(bytes_read) => body.extend_from_slice(&buffer[..bytes_read]),
                Err(error)
                    if error.kind() == io::ErrorKind::WouldBlock
                        || error.kind() == io::ErrorKind::TimedOut =>
                {
                    break;
                }
                Err(error) => return Err(error),
            }
        }
        raw_response.extend_from_slice(&body);
    }

    Ok(raw_response)
}

fn proxy_response_from_raw(raw_response: Vec<u8>) -> Response<std::io::Cursor<Vec<u8>>> {
    let Some(header_end) = raw_response
        .windows(4)
        .position(|window| window == b"\r\n\r\n")
    else {
        return bad_gateway("loopback proxy upstream returned a malformed response");
    };
    let header_bytes = &raw_response[..header_end];
    let body = raw_response[header_end + 4..].to_vec();
    let Ok(header_text) = std::str::from_utf8(header_bytes) else {
        return bad_gateway("loopback proxy upstream returned non-UTF8 response headers");
    };
    let mut lines = header_text.lines();
    let status_code = lines
        .next()
        .and_then(|status_line| status_line.split_whitespace().nth(1))
        .and_then(|code| code.parse::<u16>().ok())
        .unwrap_or(502);

    let mut response = Response::from_data(body).with_status_code(StatusCode(status_code));
    for line in lines {
        let Some((name, value)) = line.split_once(':') else {
            continue;
        };
        if name.eq_ignore_ascii_case("connection")
            || name.eq_ignore_ascii_case("content-length")
            || name.eq_ignore_ascii_case("transfer-encoding")
        {
            continue;
        }
        if let Ok(header) = Header::from_bytes(name.trim().as_bytes(), value.trim().as_bytes()) {
            response = response.with_header(header);
        }
    }
    response
}

