    fn r1_worksteal_queue_seeds_claims_and_accepts_receipts() {
        let mut state = R1WorkStealQueueState::default();
        let hint =
            valid_r1_fibonacci_hint_with_timestamp(now_ms().min(u128::from(u64::MAX)) as u64);
        let seed = seed_r1_worksteal_queue(&mut state, vec![hint.clone()]).expect("seed queue");

        assert_eq!(seed.seeded, 1);
        assert_eq!(seed.summary.pending, 1);

        let claim = claim_r1_worksteal_hint(&mut state, "did:aeon:device:r1-a", "phyle:r1-room")
            .expect("claim hint");

        assert_eq!(claim.status, "claimed");
        assert_eq!(
            claim.hint.as_ref().map(|hint| hint.hint_id.as_str()),
            Some("hint:fib:21")
        );
        assert_eq!(claim.summary.pending, 0);
        assert_eq!(claim.summary.claimed, 1);

        let receipt =
            resident_r1_worksteal_receipt_for_hint(&hint, "did:aeon:device:r1-a").expect("receipt");
        let response = accept_r1_worksteal_receipt(
            &mut state,
            R1WorkStealReceiptSubmission {
                schema_version: R1_WORKSTEAL_RECEIPT_SUBMISSION_SCHEMA_VERSION.to_string(),
                contract_id: R1_WORKSTEAL_RECEIPT_SUBMISSION_CONTRACT_ID.to_string(),
                theorem_id: R1_WORKSTEAL_RECEIPT_SUBMISSION_THEOREM_ID.to_string(),
                executable: false,
                claim_id: claim.claim_id.expect("claim id"),
                receipt,
                timestamp_ms: now_ms().min(u128::from(u64::MAX)) as u64,
                projection: build_protocol69_projection_envelope(),
            },
        )
        .expect("accept receipt");

        assert!(response.accepted);
        assert_eq!(response.summary.claimed, 0);
        assert_eq!(response.summary.accepted, 1);
        assert_eq!(
            response
                .summary
                .per_phyle
                .iter()
                .find(|summary| summary.phyle_id == "phyle:r1-room")
                .map(|summary| summary.completed_units),
            Some(1)
        );
    }

