        let frame = build_protocol69_workflow_frame(
            &workflow,
            Protocol69WorkflowAction::SelfEvaluateWhenFree,
        )
        .expect("canonical workflow frame");
        let seed_body = serde_json::to_vec(&frame).expect("frame json");
        let frames = parse_protocol69_workflow_seed_body(&seed_body).expect("parse seed body");
