        let response = accept_protocol69_agent_ack(&mut state, ack).expect("accept workflow ack");

        assert!(response.accepted);
        assert_eq!(response.summary.completed, 1);
        assert_eq!(response.summary.claimed, 0);
        assert_eq!(response.summary.rejected, 0);
