    #[test]
    fn flow_wire_response_uses_fixed_fano_xor_frame_before_probability_cache() {
        let cli = test_cli();
        let backend = GnosisFoilBackend::from_channel_witnesses(
            GnosisFoilIngress::WifiChannelWitness,
            vec![GnosisFoilChannelWitness {
                ingress: GnosisFoilIngress::WifiChannelWitness,
                channel_id: 6,
                frequency_hz: Some(2_437_000_000),
                rssi_dbm: Some(-44),
                packet_seen: true,
                cadence_ms: Some(10_000),
            }],
            20,
        );
        let certificate = backend.runtime_certificate();
        let resident_rf_fibonacci = Arc::new(Mutex::new(
            resident_rf_fibonacci_state_from_cli(&cli).expect("resident state"),
        ));
        let resident_model_forward_cache =
            Arc::new(Mutex::new(ResidentModelForwardCacheState::default()));
        let probability_runtime = FlowProbabilityRuntime::new(
            true,
            MeshProbabilityPolicy {
                min_observations: 2,
                min_concentration_bps: 10_000,
                residual_budget: 0,
                max_entries: 8,
            },
        );
        let request = FoilFlowFrame {
            stream_id: 7,
            sequence: 12,
            flags: 0,
            payload: b"/.aeon/fano-xor.bytes".to_vec(),
        };

        let cold = flow_wire_response_for_frame(
            request.clone(),
            &certificate,
            None,
            &cli,
            &resident_rf_fibonacci,
            &resident_model_forward_cache,
            &probability_runtime,
        )
        .expect("cold flow response");
        let hot = flow_wire_response_for_frame(
            request,
            &certificate,
            None,
            &cli,
            &resident_rf_fibonacci,
            &resident_model_forward_cache,
            &probability_runtime,
        )
        .expect("hot flow response");
        let surface = probability_runtime.surface();
        let expected = fano_xor_flow_packed_route_frame(7, 12, URING_FLOW_FIN, &certificate);

        match cold {
            FlowWireResponse::FixedFanoXor(bytes) => assert_eq!(bytes, expected),
            FlowWireResponse::Frame(_) => panic!("expected fixed Fano XOR wire frame"),
        }
        match hot {
            FlowWireResponse::FixedFanoXor(bytes) => assert_eq!(bytes, expected),
            FlowWireResponse::Frame(_) => panic!("expected fixed Fano XOR wire frame"),
        }
        assert_eq!(surface.observations, 0);
        assert_eq!(surface.reuse_decisions, 0);
        assert_eq!(surface.admitted_cached_responses, 0);
    }

    #[test]
    fn udp_loopback_returns_fixed_fano_xor_frame_bytes() {
        let cli = test_cli();
        let backend = GnosisFoilBackend::from_channel_witnesses(
            GnosisFoilIngress::WifiChannelWitness,
            vec![GnosisFoilChannelWitness {
                ingress: GnosisFoilIngress::WifiChannelWitness,
                channel_id: 6,
                frequency_hz: Some(2_437_000_000),
                rssi_dbm: Some(-44),
                packet_seen: true,
                cadence_ms: Some(10_000),
            }],
            20,
        );
        let certificate = backend.runtime_certificate();
        let resident_rf_fibonacci = Arc::new(Mutex::new(
            resident_rf_fibonacci_state_from_cli(&cli).expect("resident state"),
        ));
        let resident_model_forward_cache =
            Arc::new(Mutex::new(ResidentModelForwardCacheState::default()));
        let probability_runtime =
            FlowProbabilityRuntime::new(true, MeshProbabilityPolicy::default());
        let server = UdpSocket::bind("127.0.0.1:0").expect("server socket");
        let client = UdpSocket::bind("127.0.0.1:0").expect("client socket");
        server
            .set_read_timeout(Some(Duration::from_secs(1)))
            .expect("server timeout");
        client
            .set_read_timeout(Some(Duration::from_secs(1)))
            .expect("client timeout");
        let request = FoilFlowFrame {
            stream_id: 7,
            sequence: 12,
            flags: 0,
            payload: b"/.aeon/fano-xor.bytes".to_vec(),
        }
        .encode()
        .expect("request encodes");

        client
            .send_to(&request, server.local_addr().expect("server addr"))
            .expect("client sends request");
        let mut request_buffer = [0_u8; 128];
        let (request_len, peer) = server
            .recv_from(&mut request_buffer)
            .expect("server receives request");
        let decoded_request =
            FoilFlowFrame::decode(&request_buffer[..request_len]).expect("request decodes");
        let response = flow_wire_response_for_frame(
            decoded_request,
            &certificate,
            None,
            &cli,
            &resident_rf_fibonacci,
            &resident_model_forward_cache,
            &probability_runtime,
        )
        .expect("flow wire response");
        let expected = fano_xor_flow_packed_route_frame(7, 12, URING_FLOW_FIN, &certificate);

        match response {
            FlowWireResponse::FixedFanoXor(bytes) => {
                assert_eq!(bytes, expected);
                server.send_to(&bytes, peer).expect("server sends response");
            }
            FlowWireResponse::Frame(_) => panic!("expected fixed Fano XOR wire frame"),
        }

        let mut response_buffer = [0_u8; 128];
        let (response_len, _) = client
            .recv_from(&mut response_buffer)
            .expect("client receives response");
        let decoded_response =
            FoilFlowFrame::decode(&response_buffer[..response_len]).expect("response decodes");
        let surface = probability_runtime.surface();

        assert_eq!(response_len, expected.len());
        assert_eq!(&response_buffer[..response_len], &expected);
        assert_eq!(decoded_response.stream_id, 7);
        assert_eq!(decoded_response.sequence, 12);
        assert_eq!(decoded_response.flags, URING_FLOW_FIN);
        assert_eq!(decoded_response.payload, vec![1, 0, 131]);
        assert_eq!(surface.observations, 0);
    }

