    fn flow_frame_runtime_attestation_json(
        cli: &Cli,
        certificate: &GnosisFoilRuntimeCertificate,
        entropy_certificate: Option<&ResidentEntropyCertificate>,
    ) -> (FoilFlowFrame, serde_json::Value) {
        let resident_rf_fibonacci = test_resident_rf_fibonacci(cli);
        let resident_model_forward_cache = test_resident_model_forward_cache();
        let probability_runtime =
            FlowProbabilityRuntime::new(false, MeshProbabilityPolicy::default());
        let request = FoilFlowFrame {
            stream_id: 69,
            sequence: 7,
            flags: 0,
            payload: b"GET /.aeon/runtime-attestation HTTP/1.1\r\n\r\n".to_vec(),
        };

        let encoded = request.encode().expect("encode flow request");
        let decoded_request = FoilFlowFrame::decode(&encoded).expect("decode flow request");
        let response = flow_response_for_frame(
            decoded_request,
            certificate,
            entropy_certificate,
            cli,
            &resident_rf_fibonacci,
            &resident_model_forward_cache,
            &probability_runtime,
        )
        .expect("flow response");
        let encoded_response = response.encode().expect("encode flow response");
        let decoded_response =
            FoilFlowFrame::decode(&encoded_response).expect("decode flow response");
        let json =
            serde_json::from_slice(&decoded_response.payload).expect("flow attestation json");
        (decoded_response, json)
    }

