fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let cli = match parse_cli() {
        Ok(cli) => cli,
        Err(message) => {
            eprintln!("{message}");
            std::process::exit(2);
        }
    };
    let entropy_harvest_certificate = if let Some(source) = cli.entropy_harvest_jsonl.as_deref() {
        load_entropy_harvest_certificate_jsonl(source)?
    } else {
        None
    };
    let backend = if let Some(source) = cli.raw_capture_jsonl.as_deref() {
        backend_from_raw_capture_jsonl(&cli, source)?
    } else {
        default_backend(&cli)
    };
    let certificate = Arc::new(backend.runtime_certificate());
    let resident_rf_fibonacci = Arc::new(Mutex::new(
        resident_rf_fibonacci_state_from_cli(&cli).map_err(|error| {
            io::Error::new(
                io::ErrorKind::InvalidInput,
                format!("rf fibonacci resident: {error}"),
            )
        })?,
    ));
    let resident_model_forward_cache =
        Arc::new(Mutex::new(ResidentModelForwardCacheState::default()));
    let r1_worksteal_queue = Arc::new(Mutex::new(R1WorkStealQueueState::default()));
    let protocol69_workflow_queue = Arc::new(Mutex::new(Protocol69DispatchQueueState::default()));
    let protocol69_antiqueue_network = Arc::new(Mutex::new(
        Protocol69AntiqueueNetworkState::new("network:gnosis-foil-local")
            .map_err(|error| format!("protocol69 antiqueue network init failed: {error}"))?,
    ));
    let probability_runtime = Arc::new(FlowProbabilityRuntime::new(
        cli.probability_admission_enabled,
        MeshProbabilityPolicy::default(),
    ));
    let _flow_listener = spawn_flow_listener(
        &cli,
        Arc::clone(&certificate),
        entropy_harvest_certificate.clone(),
        Arc::clone(&resident_rf_fibonacci),
        Arc::clone(&resident_model_forward_cache),
        Arc::clone(&probability_runtime),
    )?;
    let bind = format!("{}:{}", cli.host, cli.port);
    let server = Server::http(&bind)?;
    eprintln!("gnosis-foil-control listening on http://{bind}");

    let cli = Arc::new(cli);
    let backend = Arc::new(backend);
    for mut request in server.incoming_requests() {
        let cli = Arc::clone(&cli);
        let backend = Arc::clone(&backend);
        let certificate = Arc::clone(&certificate);
        let entropy_harvest_certificate = entropy_harvest_certificate.clone();
        let resident_rf_fibonacci = Arc::clone(&resident_rf_fibonacci);
        let resident_model_forward_cache = Arc::clone(&resident_model_forward_cache);
        let r1_worksteal_queue = Arc::clone(&r1_worksteal_queue);
        let protocol69_workflow_queue = Arc::clone(&protocol69_workflow_queue);
        let protocol69_antiqueue_network = Arc::clone(&protocol69_antiqueue_network);
        let probability_runtime = Arc::clone(&probability_runtime);
        thread::spawn(move || {
            let route = request.url().split('?').next().unwrap_or("/");
            let response = if request.method() == &Method::Post && route == "/.aeon/protocol69" {
                handle_protocol69_post(&mut request)
            } else if request.method() == &Method::Post
                && route == "/.aeon/protocol69/workflow/seed"
            {
                handle_protocol69_workflow_seed_post(&mut request, &protocol69_workflow_queue)
            } else if request.method() == &Method::Post
                && route == "/.aeon/protocol69/workflow/claim"
            {
                handle_protocol69_workflow_claim_post(&mut request, &protocol69_workflow_queue)
            } else if request.method() == &Method::Post && route == "/.aeon/protocol69/workflow/ack"
            {
                handle_protocol69_workflow_ack_post(&mut request, &protocol69_workflow_queue)
            } else if request.method() == &Method::Post && route == "/.aeon/protocol69/network/seed"
            {
                handle_protocol69_network_seed_post(&mut request, &protocol69_antiqueue_network)
            } else if request.method() == &Method::Post
                && route == "/.aeon/protocol69/network/claim"
            {
                handle_protocol69_network_claim_post(&mut request, &protocol69_antiqueue_network)
            } else if request.method() == &Method::Post && route == "/.aeon/protocol69/network/ack"
            {
                handle_protocol69_network_ack_post(&mut request, &protocol69_antiqueue_network)
            } else if request.method() == &Method::Post && route == "/.aeon/r1-witness" {
                handle_r1_witness_post(
                    &mut request,
                    cli.activation_threshold,
                    &resident_rf_fibonacci,
                )
            } else if request.method() == &Method::Post && route == "/.aeon/r1-worksteal" {
                handle_r1_worksteal_post(&mut request)
            } else if request.method() == &Method::Post && route == "/.aeon/r1-worksteal/seed" {
                handle_r1_worksteal_seed_post(&mut request, &r1_worksteal_queue)
            } else if request.method() == &Method::Get && route == "/.aeon/r1-worksteal/claim" {
                handle_r1_worksteal_claim_get(&request, &r1_worksteal_queue)
            } else if request.method() == &Method::Post && route == "/.aeon/r1-worksteal/receipt" {
                handle_r1_worksteal_receipt_post(&mut request, &r1_worksteal_queue)
            } else if request.method() == &Method::Post && route == "/.aeon/ditto/replace" {
                handle_ditto_replacement_post(&mut request)
            } else if request.method() == &Method::Get
                && should_handle_native(route, cli.proxy_upstream.is_some())
            {
                handle_get(
                    &request,
                    &cli,
                    &backend,
                    &certificate,
                    entropy_harvest_certificate.as_ref(),
                    &resident_rf_fibonacci,
                    &resident_model_forward_cache,
                    &probability_runtime,
                )
            } else if let Some(upstream) = &cli.proxy_upstream {
                proxy_request(&mut request, upstream)
            } else if request.method() == &Method::Get {
                not_found()
            } else {
                method_not_allowed()
            };
            if let Err(error) = request.respond(response) {
                eprintln!("failed to write response: {error}");
            }
        });
    }

    Ok(())
}
